INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11501, 1, '🎮 방치형 RPG: 용사 키우기', '', '⚔️ 접속하지 않아도 폭풍 성장!\n💎 지금 접속 시 전설 등급 무기 100% 증정\n🔥 화려한 스킬과 타격감을 느껴보세요\n▶ 바로 플레이하기', '', 1190000.00, 5950),
(11502, 1, '🕹️ 추억의 오락실 게임기 특가', '', '✨ 3,000여 가지 고전 게임 내장\n📺 거실 TV에 연결만 하면 끝!\n💰 한정 수량 30% 할인 이벤트 중\n▶ 추억 여행 떠나기', '', 580000.00, 2900),
(11503, 1, '🏹 정통 MMORPG: 아르카나', '', '🌍 끝없는 오픈 월드에서의 모험\n⚔️ 대규모 공성전과 실시간 레이드\n📌 신규 서버 오픈! 경험치 2배 버프\n▶ 모험 시작하기', '', 1870000.00, 9350),
(11504, 1, '⚽ 실시간 축구 매니지먼트 2026', '', '🏆 나만의 드림팀을 구성하고 승리하세요\n📊 정교한 데이터 기반의 전술 시스템\n💰 신규 감독님께 10만 골드 지원\n▶ 구단 운영하기', '', 1260000.00, 6300),
(11505, 1, '🎴 전략 카드 배틀: 섀도우 덱', '', '🧠 두뇌 싸움의 정점, 나만의 덱 빌딩\n✨ 수려한 일러스트와 강력한 효과\n🎁 스타터 팩 50% 할인 혜택\n▶ 배틀 시작하기', '', 650000.00, 3250),
(11506, 1, '🏎️ 초고속 레이싱: 니트로 시티', '', '🔥 극한의 속도감, 리얼한 그래픽\n🏎️ 슈퍼카 커스터마이징 시스템\n📌 주말 한정 타임 어택 이벤트\n▶ 질주하기', '', 1940000.00, 9700),
(11507, 1, '🧩 힐링 퍼즐: 고양이 정원', '', '🐱 귀여운 고양이들과 함께하는 퍼즐\n✨ 정원을 꾸미고 힐링하는 시간\n💰 하트 무제한 1시간 쿠폰 증정\n▶ 정원 가꾸기', '', 1330000.00, 6650),
(11508, 1, '🔫 서바이벌 슈팅: 라스트 원', '', '🔥 100인 중 최후의 생존자가 되세요\n🚁 리얼한 탄도학 기술 적용\n📌 신규 맵 업그레이드 완료\n▶ 생존 시작하기', '', 720000.00, 3600),
(11509, 1, '🏰 성 지키기: 타워 디펜스', '', '🛡️ 끊임없이 몰려오는 적을 막아내라\n✨ 전략적인 타워 배치와 업그레이드\n💰 오늘만 특수 영웅 무료 체험\n▶ 방어 시작하기', '', 110000.00, 550),
(11510, 1, '🎹 리듬 액션: 비트 마스터', '', '🎶 최신 K-POP과 함께 즐기는 비트\n✨ 화려한 노트 효과와 랭킹 시스템\n🎁 지금 가입 시 프리미엄 곡 증정\n▶ 비트 타기', '', 1400000.00, 7000),
(11511, 1, '🧗 클라이밍 킹: 고도 제한', '', '⛰️ 손끝으로 느끼는 짜릿한 긴장감\n✨ 전 세계 명산을 정복하세요\n📌 최고 기록 갱신 시 보석 지급\n▶ 등반 시작하기', '', 790000.00, 3950),
(11512, 1, '🍳 타이쿤: 나만의 레스토랑', '', '🍱 세계 최고의 셰프에 도전하세요\n✨ 레시피 개발부터 인테리어까지\n💰 오픈 기념 웰컴 키트 증정\n▶ 요리 시작하기', '', 180000.00, 900),
(11513, 1, '🧸 몽글몽글 인형 뽑기 모바일', '', '🎁 실시간 원격 제어로 실제 인형 획득\n✨ 뽑은 인형은 집으로 무료 배송\n📌 첫 결제 시 뽑기권 10회 추가\n▶ 인형 뽑기', '', 1470000.00, 7350),
(11514, 1, '🧪 미스터리 탈출 게임: 밀실', '', '🔍 숨겨진 단서를 찾고 탈출하세요\n✨ 소름 끼치는 반전과 탄탄한 스토리\n💰 힌트 패키지 기간 한정 세일\n▶ 탈출하기', '', 860000.00, 4300),
(11515, 1, '🧟 좀비 서바이벌: 데드 시티', '', '💀 좀비 떼로부터 거점을 사수하세요\n🔧 무기 제작 및 생존자 모집\n📌 접속 시 보급상자 5개 지급\n▶ 생존하기', '', 250000.00, 1250),
(11516, 1, '🏌️ 리얼 골프 월드 챔피언십', '', '⛳ 실제 필드를 그대로 옮긴 그래픽\n✨ 정교한 스윙 메커니즘 적용\n💰 홀인원 달성 시 유료 클럽 증정\n▶ 티오프하기', '', 1540000.00, 7700),
(11517, 1, '🚢 대항해 시대: 무역의 왕', '', '🌊 전 세계를 누비는 거대 무역 상단\n⚔️ 해적 소탕과 도시 점령전\n📌 신규 선박 업그레이드 패키지\n▶ 항해 시작하기', '', 930000.00, 4650),
(11518, 1, '👻 공포의 숨바꼭질: 심야 학교', '', '😱 술래를 피해 아침까지 살아남으세요\n✨ 긴장감 넘치는 멀티플레이 모드\n💰 공포 테마 스킨 전원 증정\n▶ 게임 시작하기', '', 320000.00, 1600),
(11519, 1, '🐉 드래곤 길들이기: 진화', '', '🔥 전설의 드래곤을 부화시키세요\n✨ 화려한 진화 단계와 강력한 스킬\n📌 전설 알 부화 확률 UP 이벤트\n▶ 육성하기', '', 1610000.00, 8050),
(11520, 1, '🏀 길거리 농구: 슬램덩크', '', '🔥 3대3 실시간 매칭 농구 배틀\n✨ 화려한 덩크슛과 개인기 디테일\n💰 신규 유저 코스튬 세트 증정\n▶ 코트 입장하기', '', 1000000.00, 5000),
(11521, 1, '🐹 햄스터 마을 키우기', '', '✨ 작고 소중한 햄스터들의 안식처\n💖 보기만 해도 힐링되는 방치형 게임\n📌 지금 시작하면 프리미엄 집 증정\n▶ 마을 만들기', '', 390000.00, 1950),
(11522, 1, '🀄 클래식 맞고: 신의 한 수', '', '💰 짜릿한 손맛과 대박의 기회\n✨ 무제한 게임 머니 무료 충전\n📌 매일 출석 시 행운의 복권 증정\n▶ 한판 하기', '', 1680000.00, 8400),
(11523, 1, '🧚 동화 나라 어드벤처', '', '🌸 동화 속 주인공들과 함께하는 여행\n✨ 아름다운 그래픽과 감동적인 스토리\n💰 신규 모험가 특별 패키지\n▶ 모험 떠나기', '', 1070000.00, 5350),
(11524, 1, '🛸 우주 전쟁: 갤럭시 가디언', '', '🌌 은하계를 수호하는 함대 사령관\n✨ 거대 전함 커스터마이징 시스템\n📌 함선 업그레이드 부품 지원\n▶ 우주로 출발', '', 460000.00, 2300),
(11525, 1, '🛹 스케이트보드 마스터', '', '🔥 도심 속 화려한 트릭을 선보이세요\n✨ 나만의 보드 커스텀 기능\n💰 랭킹 이벤트 우승자 경품 증정\n▶ 보드 타기', '', 1750000.00, 8750),
(11526, 1, '🎣 도시어부 모바일: 대어 낚시', '', '🌊 전국 팔도 낚시 명소 완벽 재현\n✨ 릴을 감는 묵직한 손맛 구현\n📌 전설의 물고기 포획 확률 UP\n▶ 낚시 시작하기', '', 1140000.00, 5700),
(11527, 1, '🦸 히어로 아카데미: 각성', '', '🔥 나만의 히어로 팀을 결성하세요\n⚔️ 속성별 상성을 이용한 전략 전투\n💰 무료 소환 100회 이벤트 중\n▶ 각성하기', '', 530000.00, 2650),
(11528, 1, '🏢 빌딩 타이쿤: 건물주 되기', '', '💰 강남에 내 건물을 세워보세요\n✨ 월세 수익으로 자산가 도전\n📌 신규 유저 투자 지원금 지급\n▶ 경영하기', '', 1820000.00, 9100),
(11529, 1, '🚜 농장 경영: 해피 팜', '', '🌽 정성껏 기른 작물로 수익 창출\n✨ 귀여운 가축들과 함께하는 농촌 생활\n💰 농기구 세트 무료 업그레이드\n▶ 농사 짓기', '', 1210000.00, 6050),
(11530, 1, '🎱 당구 마스터: 3쿠션 전설', '', '✨ 정교한 물리 엔진의 당구 시뮬레이션\n🏆 실시간 1대1 온라인 대전\n📌 큐대 스킨 무료 제공 이벤트\n▶ 당구장 가기', '', 600000.00, 3000),
(11531, 1, '🦊 요괴 연대기: 식신 소환', '', '✨ 신비로운 요괴들과의 계약\n⚔️ 턴제 방식의 깊이 있는 전략성\n💰 소환권 50장 패키지 특가\n▶ 소환하기', '', 1890000.00, 9450),
(11532, 1, '⛏️ 광부 키우기: 지구 중심까지', '', '💎 땅을 파서 보석을 캐고 부자 되기\n✨ 자동 채굴 시스템으로 편하게\n📌 황금 곡괭이 강화 확률 UP\n▶ 채굴 시작하기', '', 1280000.00, 6400),
(11533, 1, '🎨 컬러링 퍼즐: 명화 완성', '', '✨ 숫자에 맞춰 색을 칠하는 힐링 게임\n💖 완성된 작품으로 갤러리 꾸미기\n💰 프리미엄 도안 무료 개방\n▶ 색칠하기', '', 670000.00, 3350),
(11534, 1, '🚒 긴급출동! 소방관 시뮬레이터', '', '🔥 생명을 구하는 영웅이 되어보세요\n✨ 긴박한 화재 현장 완벽 구현\n📌 소방차 장비 풀세트 지급\n▶ 출동하기', '', 1960000.00, 9800),
(11535, 1, '🏰 삼국지: 천하통일 전략전', '', '⚔️ 조조, 유비, 손권과 함께하는 대권\n✨ 천하를 다투는 치열한 지략 대결\n📌 신규 군주님께 명마 증정\n▶ 출진하기', '', 1350000.00, 6750),
(11536, 1, '🐱 고양이 카페 운영하기', '', '☕ 귀여운 고양이 손님들이 가득\n✨ 카페 인테리어와 디저트 개발\n💰 집사 전용 한정 가구 선물\n▶ 카페 열기', '', 740000.00, 3700),
(11537, 1, '🏃 무한의 계단: 챌린지', '', '🔥 중독성 강한 탭 타이밍 게임\n✨ 전 세계 유저와 기록 경쟁\n💰 신규 캐릭터 스킨 즉시 지급\n▶ 올라가기', '', 130000.00, 650),
(11538, 1, '🧙 마법사 키우기: 대마법사', '', '✨ 화려한 광역 마법으로 몬스터 소탕\n🔥 끝없는 마법 연구와 강화\n📌 마나 무제한 물약 증정 중\n▶ 마법 배우기', '', 1420000.00, 7100),
(11539, 1, '🏹 활잡이 키우기: 신궁의 길', '', '🎯 백발백중! 쏟아지는 화살의 쾌감\n✨ 다양한 속성 화살 조합 시스템\n💰 신규 유저 명궁 활 증정\n▶ 활 쏘기', '', 810000.00, 4050),
(11540, 1, '🦒 동물원 타이쿤: 쥬 랜드', '', '🦁 전 세계 희귀 동물을 한 곳에\n✨ 관람객 유치를 위한 테마파크 조성\n📌 아기 사자 분양권 100% 증정\n▶ 개장하기', '', 200000.00, 1000),
(11541, 1, '⚔️ 소드 마스터: 각성하는 검', '', '🔥 초고속 액션 RPG의 정점\n✨ 화려한 콤보와 궁극기 이펙트\n💰 지금 접속 시 전설 검 선택권\n▶ 검술 연마하기', '', 1490000.00, 7450),
(11542, 1, '🚆 열차 시뮬레이터: 서울역', '', '🛤️ 실제 기차 노선을 달리는 현실감\n✨ 기관사가 되어 안전하게 운행하세요\n📌 KTX 테마 열차 기간 한정 공개\n▶ 운전 시작하기', '', 880000.00, 4400),
(11543, 1, '🛸 에일리언 슈터: 지구 침공', '', '👽 외계인의 침공으로부터 지구 사수\n✨ 강력한 미래형 화기 업그레이드\n💰 유료 강화석 100개 지원 쿠폰\n▶ 사격하기', '', 270000.00, 1350),
(11544, 1, '👗 패션 스타: 모델 오디션', '', '✨ 화려한 코디로 런웨이를 장악하세요\n💖 나만의 스타일링과 메이크업\n📌 명품 브랜드 의상 세트 증정\n▶ 코디하기', '', 1560000.00, 7800),
(11545, 1, '🛡️ 방패 용사 디펜스', '', '⚔️ 공격보다 강력한 방패의 힘\n✨ 몰려오는 보스 몬스터를 막아라\n💰 방어구 강화 키트 1+1 이벤트\n▶ 수비하기', '', 950000.00, 4750),
(11546, 1, '🏔️ 생존 서바이벌: 설산의 고독', '', '❄️ 영하 40도, 극한 환경에서의 생존\n✨ 사냥과 채집을 통한 거점 구축\n📌 방한 장비 세트 무료 지급\n▶ 살아남기', '', 340000.00, 1700),
(11547, 1, '🃏 포커 스타: 월드 투어', '', '💰 전 세계 고수들과의 심리전\n✨ 긴장감 넘치는 정통 홀덤 배틀\n📌 매일 1억 골드 판돈 지원\n▶ 베팅하기', '', 1630000.00, 8150),
(11548, 1, '🐹 햄스터 회전목마 파크', '', '🎡 햄스터들의 놀이공원을 만드세요\n✨ 귀여움 한도 초과 방치형 힐링\n💰 황금 해바라기씨 500개 지급\n▶ 건설하기', '', 1020000.00, 5100),
(11549, 1, '🧙 미소녀 마법 기사단: 수집', '', '✨ 아름다운 일러스트의 기사단 모집\n⚔️ 화려한 연계 스킬과 전략 전투\n🎁 신규 유저 100회 무료 뽑기\n▶ 기사단 모집', '', 410000.00, 2050),
(11550, 1, '🚔 경찰 시뮬레이터: 강력반', '', '🚨 도심의 평화를 지키는 경찰관\n✨ 추격전부터 범인 검거까지\n📌 경찰차 사이렌 스킨 증정\n▶ 순찰 시작하기', '', 1700000.00, 8500);
