INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11651, 1, '🏰 다크 소울즈: 심연의 왕좌', '', '🔥 절망적인 난이도, 그러나 멈출 수 없는 쾌감\n⚔️ 보스 패턴을 파악하고 승리를 쟁취하세요\n📌 사전 예약 시 한정판 코스튬 증정\n▶ 도전하기', '', 890000.00, 4450),
(11652, 1, '🧩 젤리 팝: 달콤한 매치 3', '', '🍭 화려한 콤보가 터지는 짜릿한 퍼즐\n✨ 2,000개 이상의 방대한 스테이지\n💰 신규 유저 무제한 하트 2시간 제공\n▶ 퍼즐 시작', '', 280000.00, 1400),
(11653, 1, '🚀 갤럭시 오디세이: 행성 개척', '', '🌌 미지의 행성을 탐사하고 자원을 채집하세요\n✨ 나만의 우주 기지를 건설하고 방어하기\n📌 스타터 함선 무료 업그레이드 지원\n▶ 우주로 출발', '', 1570000.00, 7850),
(11654, 1, '⚽ 풋볼 매니지먼트 2026 PRO', '', '🏆 당신이 꿈꾸던 최고의 구단을 만드세요\n📊 실시간 이적 시장 반영 및 전술 시뮬레이션\n💰 전설의 감독 팩 즉시 지급 쿠폰\n▶ 구단주 되기', '', 960000.00, 4800),
(11655, 1, '🗡️ 도트 판타지: 용사 키우기', '', '✨ 고퀄리티 2D 도트 액션의 진수\n🔥 수집욕을 자극하는 200종의 영웅들\n🎁 지금 접속 시 다이아 3,000개 증정\n▶ 모험 떠나기', '', 350000.00, 1750),
(11656, 1, '🏢 버거 타이쿤: 맛집의 탄생', '', '🍔 나만의 레시피로 수제 버거 프랜차이즈 도전\n✨ 몰려드는 손님들을 만족시키고 매장 확장\n💰 오픈 기념 황금 뒤집개 아이템 증정\n▶ 경영 시작', '', 1640000.00, 8200),
(11657, 1, '🔫 모던 워페어: 특수 부대', '', '🎯 초정밀 그래픽으로 구현된 밀리터리 슈팅\n✨ 전 세계 유저와 즐기는 실시간 팀 데스매치\n📌 신규 총기 「K-2 커스텀」 업데이트\n▶ 사격 시작', '', 1030000.00, 5150),
(11658, 1, '🐱 고양이 마을: 힐링 아일랜드', '', '🏝️ 귀여운 고양이들과 함께하는 평화로운 일상\n✨ 섬을 꾸미고 고양이 손님들을 맞이하세요\n💰 웰컴 기프트로 프리미엄 캣닙 지급\n▶ 힐링 시작', '', 420000.00, 2100),
(11659, 1, '🏹 활의 전설: 그림자 궁수', '', '🎯 단 한 발의 화살로 적을 제압하라\n✨ 로그라이크 방식의 무한 스테이지 도전\n📌 전설 등급 활 제작 재료 지원\n▶ 활 쏘기', '', 1710000.00, 8550),
(11660, 1, '🧟 데드 좀비: 최후의 방어선', '', '💀 인류의 마지막 희망이 되어 좀비를 막으세요\n🔧 무기 개조 시스템과 생존자 캠프 구축\n💰 초보 생존자 전용 전투 보급품 증정\n▶ 생존하기', '', 1100000.00, 5500),
(11661, 1, '🎹 댄싱 비트: 케이팝 스타', '', '🎶 좋아하는 아이돌 곡을 리듬으로 즐기세요\n✨ 화려한 아바타 커스텀과 댄스 배틀\n🎁 프리미엄 멤버십 7일 체험권 증정\n▶ 리듬 타기', '', 490000.00, 2450),
(11662, 1, '🚜 농장 이야기: 해피 빌리지', '', '🌽 정성껏 가꾼 작물로 마을을 번성시키세요\n✨ 귀여운 동물들과 함께하는 힐링 농장 경영\n💰 창고 확장 비용 30% 한정 할인\n▶ 농사 짓기', '', 1780000.00, 8900),
(11663, 1, '🧗 클라이밍 챔피언: 수직 한계', '', '⛰️ 손에 땀을 쥐게 하는 절벽 등반 액션\n✨ 전 세계 유명 산을 정복하고 랭킹 도전\n📌 클라이밍 슈즈 강화 아이템 증정\n▶ 등반하기', '', 1170000.00, 5850),
(11664, 1, '🧪 미스터리 룸: 탈출의 귀재', '', '🕵️ 당신의 지능을 시험하는 고난도 퍼즐\n✨ 숨겨진 단서를 찾아 방을 탈출하세요\n💰 힌트 팩 무제한 이용권 주말 특가\n▶ 탈출 시작', '', 560000.00, 2800),
(11665, 1, '🚢 해적왕의 항해: 보물을 찾아서', '', '🌊 거대한 범선을 타고 미지의 바다를 탐험\n⚔️ 해상 전투와 섬 약탈의 짜릿한 재미\n📌 보물지도 조각 100% 증정 이벤트\n▶ 항해 시작', '', 1850000.00, 9250),
(11666, 1, '🏌️ 골프 킹: 온라인 토너먼트', '', '⛳ 실제 필드의 현장감을 모바일로 그대로\n✨ 전 세계 유저와 실시간 1:1 대결\n💰 홀인원 경품 응모권 매일 증정\n▶ 티오프', '', 1240000.00, 6200),
(11667, 1, '🐉 드래곤 에그: 부화의 시작', '', '🔥 전설의 드래곤을 부화시키고 훈련하세요\n✨ 다양한 속성의 드래곤을 수집하는 재미\n📌 희귀 알 부화 가속기 5개 지급\n▶ 육성하기', '', 630000.00, 3150),
(11668, 1, '🏀 바스켓 루키: 덩크 마스터', '', '🔥 길거리 농구의 화려한 기술을 내 손안에\n✨ 나만의 선수를 육성하고 리그 우승 도전\n💰 신규 유저용 유니폼 세트 증정\n▶ 경기 시작', '', 1920000.00, 9600),
(11669, 1, '🐹 햄스터 쉐프: 맛있는 식당', '', '🥖 귀여운 햄스터 쉐프들의 우당탕탕 요리\n✨ 레스토랑 인테리어와 메뉴 개발의 재미\n💰 최고급 식재료 박스 10개 선물\n▶ 요리 시작', '', 1310000.00, 6550),
(11670, 1, '🀄 맞고 고수: 판돈을 키워라', '', '💰 짜릿한 타격감과 심리전의 묘미\n✨ 끊이지 않는 무료 충전 서비스\n📌 오늘 가입 시 VIP 아바타 증정\n▶ 한판 하기', '', 700000.00, 3500),
(11671, 1, '🧚 머지 가든: 정령의 숲', '', '✨ 같은 꽃을 합쳐서 더 큰 정원을 만드세요\n🌸 지친 일상 속 힐링을 선사하는 퍼즐\n💰 정원 확장 아이템 50% 세일\n▶ 가꾸기', '', 1990000.00, 9950),
(11672, 1, '🛸 에일리언 샷: 지구 방위군', '', '🌌 지구를 위협하는 외계인 함대를 섬멸하라\n✨ 화려한 탄막 액션과 기체 개조 시스템\n📌 강화 주문서 100장 즉시 지급\n▶ 출격하기', '', 1380000.00, 6900),
(11673, 1, ' skate 🛹 스케이트 파크: 자유 질주', '', '🔥 도심 속 장애물을 화려한 트릭으로 통과\n✨ 나만의 보드 디자인과 기술 커스텀\n💰 랭킹 이벤트 참여 시 한정판 데크 증정\n▶ 보드 타기', '', 770000.00, 3850),
(11674, 1, '🎣 빅 피시: 대어의 꿈', '', '🌊 전 세계의 바다에서 즐기는 리얼 낚시\n✨ 짜릿한 손맛과 도감 채우기의 성취감\n📌 전설의 미끼 세트 1주일 체험권\n▶ 낚시 시작', '', 160000.00, 800),
(11675, 1, '🦸 울트라 히어로: 악당 소탕', '', '🔥 강력한 히어로 군단을 결성하세요\n⚔️ 세상을 구하는 거대 보스 레이드전\n💰 유료 캐릭터 선택권 무료 배포\n▶ 각성하기', '', 1450000.00, 7250),
(11676, 1, '🏢 랜드마크 타이쿤: 도시 개발', '', '💰 전 세계 랜드마크를 내 소유로!\n✨ 부동산 투자로 엄청난 수익을 창출하세요\n📌 신규 유저 투자금 2배 부스터 지급\n▶ 경영 시작', '', 840000.00, 4200),
(11677, 1, '🚜 마이 리틀 팜: 시골 풍경', '', '🌽 땀 흘리는 즐거움, 풍성한 수확의 계절\n✨ 이웃과 작물을 나누고 소통하는 재미\n💰 프리미엄 트랙터 3일 무료 대여\n▶ 농사 시작', '', 230000.00, 1150),
(11678, 1, '🎱 당구 전설: 온라인 챌린지', '', '✨ 0.1도의 오차도 허용하지 않는 정교함\n🏆 실시간 랭킹 시스템과 1:1 대전\n📌 한정판 큐대 조각 획득 이벤트\n▶ 경기 시작', '', 1520000.00, 7600),
(11679, 1, '🦊 신선기: 요괴의 복수', '', '✨ 신비로운 동양 판타지 세계로의 초대\n⚔️ 화려한 도술 액션과 수집형 RPG\n💰 7일 출석 시 전설 동료 100% 증정\n▶ 수행 시작', '', 910000.00, 4550),
(11680, 1, '⛏️ 드릴 킹: 지구를 뚫어라', '', '💎 땅속 깊이 숨겨진 보석을 찾아내세요\n✨ 드릴 강화와 자동 채굴 로봇 시스템\n📌 연료 충전 아이템 100개 지급\n▶ 채굴 시작', '', 300000.00, 1500),
(11681, 1, '🎨 픽셀 컬러링: 숫자의 마법', '', '✨ 스트레스 없는 무념무상의 색칠 시간\n💖 귀여운 픽셀 캐릭터들을 완성하세요\n💰 모든 프리미엄 도안 기간 한정 무료\n▶ 색칠하기', '', 1590000.00, 7950),
(11682, 1, '🚒 파이어 파이터: 긴급 구조', '', '🔥 불길을 뚫고 시민을 구출하는 영웅\n✨ 실제 소방차 운전 및 화재 진압 시뮬레이션\n📌 소방대원 장비 세트 무료 지급\n▶ 출동하기', '', 980000.00, 4900),
(11683, 1, '🏰 삼국지 무쌍: 난세의 영웅', '', '⚔️ 한 화면을 가득 채우는 적들을 베어라\n✨ 역사 속 무장들이 펼치는 화려한 액션\n📌 전설의 명마 「적토마」 증정\n▶ 참전하기', '', 370000.00, 1850),
(11684, 1, '🐱 냐옹 빵집: 제빵 마스터', '', '☕ 귀여운 고양이들과 함께 빵을 구워요\n✨ 달콤한 빵 냄새가 가득한 힐링 카페\n💰 인테리어 소품 세트 무료 선물\n▶ 카페 개업', '', 1660000.00, 8300),
(11685, 1, '🏃 시티 러너: 지하철 질주', '', '🔥 장애물을 피해 끝없이 달리는 짜릿함\n✨ 친구보다 더 멀리, 더 빠르게 도전하세요\n💰 캐릭터 부스트 팩 즉시 지급\n▶ 달리기', '', 1050000.00, 5250),
(11686, 1, '🧙 대마법사: 스펠 마스터', '', '✨ 쏟아지는 화려한 마법의 향연\n🔥 마법 지팡이 커스텀과 스킬 연구\n📌 마법의 가루 1,000개 지원 쿠폰\n▶ 마법 시작', '', 440000.00, 2200),
(11687, 1, '🏹 명궁: 궁수의 전설', '', '🎯 단 한 발로 승부를 가르는 고요한 긴장감\n✨ 온라인 실시간 양궁 랭킹전 지원\n💰 전용 화살통 스킨 무료 배포\n▶ 활 쏘기', '', 1730000.00, 8650),
(11688, 1, '🦒 사파리 타이쿤: 동물 보호', '', '🦁 멸종 위기 동물을 구하고 보호하세요\n✨ 나만의 사파리 파크를 만드는 즐거움\n📌 아기 기린 분양권 즉시 증정\n▶ 공원 열기', '', 1120000.00, 5600),
(11689, 1, '⚔️ 소드 레전드: 각성', '', '🔥 타격감 폭발하는 액션 RPG의 완성형\n✨ 화려한 콤보와 실시간 PVP 대전\n💰 강화 성공률 UP 버프권 지급\n▶ 검술 연마', '', 510000.00, 2550),
(11690, 1, '🚆 지하철 기관사: 리얼 운행', '', '🛤️ 서울에서 부산까지 실제 노선 구현\n✨ 기관실 내부의 세밀한 조작감 체험\n📌 신규 노선 프리 패스권 제공\n▶ 운전 시작', '', 1800000.00, 9000),
(11691, 1, '🛸 에일리언 슈팅: 대전쟁', '', '👽 끊임없이 쏟아지는 외계 함대 격파\n✨ 무기 조합을 통한 자신만의 공격 패턴\n💰 보석 2,000개 즉시 지급 이벤트\n▶ 사격하기', '', 1190000.00, 5950),
(11692, 1, '👗 패션 스타: 모델의 길', '', '✨ 화려한 런웨이, 당신이 바로 주인공\n💖 최신 트렌드 의상으로 코디하세요\n📌 명품 코트 아이템 전원 증정\n▶ 코디 시작', '', 580000.00, 2900),
(11693, 1, '🛡️ 캐슬 가디언: 최후의 요새', '', '⚔️ 몰려오는 몬스터들을 성벽 위에서 저지\n✨ 영웅과 타워의 완벽한 전략 조합\n💰 타워 건설 시간 단축 물약 증정\n▶ 수비하기', '', 1870000.00, 9350),
(11694, 1, '🏔️ 설산의 생존자: 아이스 에이지', '', '❄️ 영하의 기온에서 불을 지피고 살아남기\n✨ 야생 동물을 사냥하고 거점을 구축하세요\n📌 방한 패키지 100% 무료 지원\n▶ 생존 시작', '', 1260000.00, 6300),
(11695, 1, '🃏 포커 토너먼트: 챔피언십', '', '💰 세계 최고의 포커 고수들과의 진검 승부\n✨ 공정한 시스템과 압도적인 긴장감\n📌 신규 가입 시 칩 5억 개 증정\n▶ 베팅하기', '', 650000.00, 3250),
(11696, 1, '🐹 햄찌 레이스: 달리기 대전', '', '🏃 세상에서 제일 빠른 햄스터를 키우세요\n✨ 다양한 코스와 장애물을 돌파하는 재미\n💰 해바라기씨 럭키 박스 지급\n▶ 경기 시작', '', 1940000.00, 9700),
(11697, 1, '🧙 여신 강림: 수집형 RPG', '', '✨ 신비로운 여신들과 떠나는 아름다운 모험\n⚔️ 감동적인 스토리와 전략적인 전투\n🎁 무료 뽑기 100회권 즉시 제공\n▶ 소환하기', '', 1330000.00, 6650),
(11698, 1, '🚔 경찰 특공대: 테러 진압', '', '🚨 도심의 평화를 위협하는 적들을 소탕하라\n✨ 박진감 넘치는 총격전과 전술 액션\n📌 특수 방탄복 아이템 무료 증정\n▶ 수사 시작', '', 720000.00, 3600),
(11699, 1, '🎮 미니 게임 월드: 99가지 재미', '', '🕹️ 한 번 시작하면 멈출 수 없는 미니 게임들\n✨ 친구와 점수 경쟁하고 기록 세우기\n💰 하트 무제한 충전 버프 지급\n▶ 게임 선택', '', 110000.00, 550),
(11700, 1, '🧚 요정의 숲: 시크릿 가든', '', '🌸 잃어버린 요정들의 안식처를 되찾으세요\n✨ 식물을 키우고 숲을 복원하는 힐링\n💰 정원 데코레이션 풀세트 증정\n▶ 가꾸기', '', 1400000.00, 7000);
