INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11701, 1, '🏰 다크 판타지: 소울 레이드', '', '🔥 죽음조차 두렵지 않은 하드코어 액션\n⚔️ 거대 보스와의 숨막히는 컨트롤 대결\n📌 지금 접속 시 심연의 망토 증정\n▶ 도전하기', '', 790000.00, 3950),
(11702, 1, '🧩 과일 팡팡: 스윗 매치 3', '', '🍓 상큼한 과일들이 톡톡 터지는 재미\n✨ 1,000개가 넘는 다양한 스테이지\n💰 하트 무제한 30분 즉시 지급\n▶ 퍼즐 풀기', '', 180000.00, 900),
(11703, 1, '🚀 갤럭시 임파이어: 개척자', '', '🌌 미지의 행성을 탐사하고 기지를 건설하세요\n✨ 우주 함대 지휘 및 대규모 자원 전쟁\n📌 신규 사령관 정착 지원금 지급\n▶ 우주 항해', '', 1470000.00, 7350),
(11704, 1, '⚽ 풋볼 스타 2026: 리그전', '', '🏆 당신의 손끝에서 터지는 환상적인 골\n📊 실시간 이적 시장과 구단 관리 시스템\n💰 전설의 선수 카드 팩 100% 증정\n▶ 경기 시작', '', 860000.00, 4300),
(11705, 1, '🗡️ 도트 용사: 레트로 어드벤처', '', '✨ 추억을 자극하는 고퀄리티 도트 그래픽\n🔥 수집형 RPG의 정석, 300종의 영웅들\n🎁 신규 유저 7일간의 선물 축제\n▶ 모험 떠나기', '', 250000.00, 1250),
(11706, 1, '🏢 편의점 타이쿤: 골드 점주', '', '🏪 24시간 잠들지 않는 나만의 편의점\n✨ 손님 취향 저격 물건 배치와 알바 관리\n💰 오픈 기념 황금 금고 아이템 증정\n▶ 경영 시작', '', 1540000.00, 7700),
(11707, 1, '🔫 택티컬 슈팅: 고스트 분대', '', '🎯 단 한 발의 총성으로 전장을 지배하라\n✨ 리얼한 총기 커스텀과 팀 전술 시스템\n📌 야간 작전 맵 신규 업데이트 완료\n▶ 교전 시작', '', 930000.00, 4650),
(11708, 1, '🐱 고양이 섬 키우기: 방치형', '', '🏖️ 평화로운 섬에서 즐기는 냥이들과의 휴식\n✨ 낚시하고 요리하며 섬을 꾸며보세요\n💰 접속 시 고급 캣타워 즉시 지급\n▶ 힐링하기', '', 320000.00, 1600),
(11709, 1, '🏹 고수들의 궁술: 킹오브 아처', '', '🎯 바람의 흐름을 읽고 과녁을 꿰뚫으세요\n✨ 실시간 온라인 1:1 양궁 대전\n📌 한정판 화살 스킨 증정 이벤트\n▶ 활 쏘기', '', 1610000.00, 8050),
(11710, 1, '🧟 좀비 언데드: 최후의 요새', '', '💀 무너진 세상, 당신만이 유일한 희망\n🔧 무기 제작부터 생존자 기지 구축까지\n💰 초보 생존자용 보급 상자 지원\n▶ 요새 사수', '', 1000000.00, 5000),
(11711, 1, '🎹 비트 파티: 아이돌 퍼포먼스', '', '🎶 최신 곡과 함께 즐기는 화려한 리듬\n✨ 나만의 아바타 코디와 댄스 배틀\n🎁 프리미엄 음원권 5회권 증정\n▶ 리듬 타기', '', 390000.00, 1950),
(11712, 1, '🚜 목장 이야기: 팜 빌리지', '', '🌽 땀 흘려 가꾼 농작물의 뿌듯함\n✨ 귀여운 동물들과 함께하는 전원 생활\n💰 농장 확장 비용 50% 세일 진행\n▶ 농사 짓기', '', 1680000.00, 8400),
(11713, 1, '🧗 절벽 위의 등반가: 챌린지', '', '⛰️ 한계에 도전하는 짜릿한 등반 액션\n✨ 전 세계 유명 절벽 완벽 구현\n📌 기록 갱신 시 다이아몬드 지급\n▶ 등반하기', '', 1070000.00, 5350),
(11714, 1, '🧪 미스테리 연구소: 탈출구', '', '🔍 단서를 조합하여 진실을 밝혀내세요\n✨ 소름 돋는 분위기와 천재적인 트릭\n💰 힌트 패키지 첫 결제 100원\n▶ 탈출 시작', '', 460000.00, 2300),
(11715, 1, '🚢 월드 오브 해적: 보물선', '', '🌊 드넓은 바다를 지배하는 진정한 해적\n⚔️ 함선 업그레이드와 약탈의 재미\n📌 전설의 블랙펄 함선 배포 중\n▶ 항해 시작', '', 1750000.00, 8750),
(11716, 1, '🏌️ 판타지 골프: 매직 샷', '', '⛳ 마법 기술을 사용해 홀인원 도전!\n✨ 화려한 스킬과 환상적인 필드 그래픽\n💰 신규 유저 마법 골프공 세트 증정\n▶ 티오프', '', 1140000.00, 5700),
(11717, 1, '🐉 드래곤 빌리지: 수집가', '', '🔥 500여 종의 신비로운 드래곤 수집\n✨ 알에서 성체까지 정성껏 키워보세요\n📌 희귀 드래곤 알 부화 이벤트 중\n▶ 육성 시작', '', 530000.00, 2650),
(11718, 1, '🏀 스트릿 후프: 길거리 농구', '', '🔥 3분간 펼쳐지는 불꽃 튀는 덩크 슛\n✨ 힙한 스트릿 감성의 코스튬과 사운드\n💰 랭킹 보상으로 유료 캐시 지급\n▶ 경기장 가기', '', 1820000.00, 9100),
(11719, 1, '🐹 햄스터 빵집 키우기', '', '🍞 꼬물꼬물 햄스터들이 굽는 맛있는 빵\n✨ 세상에서 가장 귀여운 빵집 경영\n💰 신상 오븐 장비 무료 업그레이드\n▶ 빵 굽기', '', 1210000.00, 6050),
(11720, 1, '🀄 맞고의 제왕: 올인 전략', '', '💰 짜릿한 역전의 맛, 신개념 맞고\n✨ 무제한 게임머니와 데일리 보너스\n📌 지금 접속 시 황금패 스킨 증정\n▶ 한판 하기', '', 600000.00, 3000),
(11721, 1, '🧚 정령의 숲: 머지 어드벤처', '', '✨ 같은 물건을 합쳐 숲을 되살리세요\n🌸 힐링 그 자체, 아름다운 정령들의 세계\n💰 머지 속도 강화 버프권 지급\n▶ 숲 살리기', '', 1890000.00, 9450),
(11722, 1, '🛸 에일리언 디펜스: 타워 업', '', '🌌 외계 생명체의 공격을 완벽히 방어\n✨ 다양한 속성 타워와 업그레이드 트리\n📌 주말 한정 특수 영웅 개방\n▶ 방어하기', '', 1280000.00, 6400),
(11723, 1, '🛹 스케이트 시티: 트릭 마스터', '', '🔥 도심의 모든 지형물이 당신의 무대\n✨ 실시간 점수 경쟁과 콤보 시스템\n💰 보드 커스텀 데칼 세트 증정\n▶ 질주하기', '', 670000.00, 3350),
(11724, 1, '🎣 도시 낚시꾼: 세계 투어', '', '🌊 한강부터 하와이까지 낚시 포인트 완벽\n✨ 묵직한 손맛과 대어 낚시의 쾌감\n📌 전설의 낚시찌 무료 체험권\n▶ 낚시 가기', '', 1960000.00, 9800),
(11725, 1, '🦸 히어로 시티: 무한 각성', '', '🔥 도시를 구하는 나만의 히어로 팀\n⚔️ 화려한 스킬 연계와 강력한 보스전\n💰 무료 소환 10회권 매일 증정\n▶ 각성하기', '', 1350000.00, 6750),
(11726, 1, '🏢 갓물주 타이쿤: 월세 수령', '', '💰 건물 관리하고 월세로 부자 되기\n✨ 부동산 투자와 상권 분석의 재미\n📌 신규 건물주 지원금 1억 골드\n▶ 경영하기', '', 740000.00, 3700),
(11727, 1, '🚜 해피 팜: 유기농 농장', '', '🌽 정성으로 키우는 무공해 작물들\n✨ 마을 주민들과 교류하며 농장 키우기\n💰 희귀 씨앗 꾸러미 즉시 지급\n▶ 농장 열기', '', 130000.00, 650),
(11728, 1, '🎱 당구 챔피언: 8볼 라이브', '', '✨ 물리 법칙이 완벽한 정통 당구 게임\n🏆 전 세계 유저와 실시간 대결\n📌 승리 시 한정판 큐대 조각 지급\n▶ 경기 시작', '', 1420000.00, 7100),
(11729, 1, '🦊 요괴전: 신선이 되는 길', '', '✨ 신비로운 요괴들과 함께하는 수행\n⚔️ 방치만 해도 신선으로 승급!\n💰 7일 접속 시 전설 요괴 확정 증정\n▶ 수행 시작', '', 810000.00, 4050),
(11730, 1, '⛏️ 드릴 마스터: 지하 탐험', '', '💎 드릴로 땅을 파고 숨겨진 유물 찾기\n✨ 끝없는 지하 세계와 강력한 드릴 강화\n📌 에너지 무한 물약 1시간 증정\n▶ 탐사하기', '', 200000.00, 1000),
(11731, 1, '🎨 픽셀 아트: 힐링 컬러링', '', '✨ 점을 찍으며 완성하는 나만의 예술\n💖 복잡한 생각 없이 즐기는 힐링 시간\n💰 인기 도안 50종 무료 잠금 해제\n▶ 색칠하기', '', 1490000.00, 7450),
(11732, 1, '🚒 소방대원: 인명 구조 대작전', '', '🔥 불길 속에서 생명을 구하는 영웅\n✨ 실제 소방 장비와 차량 운용 시뮬레이션\n📌 소방서 홍보 모델 스킨 증정\n▶ 출동하기', '', 880000.00, 4400),
(11733, 1, '🏰 삼국지: 영웅들의 패권', '', '⚔️ 역사 속 무장들과 함께 천하 통일\n✨ 전략적인 부대 배치와 심리전\n📌 신규 가입 시 조자룡 영웅 증정\n▶ 참전하기', '', 270000.00, 1350),
(11734, 1, '🐱 냥냥 카페: 디저트 장인', '', '☕ 귀여운 고양이 알바생들과 카페 운영\n✨ 세상에서 가장 달콤한 디저트 레시피\n💰 한정판 인테리어 가구 세트\n▶ 카페 개업', '', 1560000.00, 7800),
(11735, 1, '🏃 무한의 달리기: 시티 런', '', '🔥 장애물을 피해 끝없이 질주하세요\n✨ 중독성 강한 조작과 캐릭터 수집\n💰 신규 캐릭터 런닝화 아이템 증정\n▶ 달리기', '', 950000.00, 4750),
(11736, 1, '🧙 대마법사 키우기: 무한 마나', '', '✨ 화면을 가득 채우는 화려한 마법\n🔥 강력한 지팡이와 마법서 수집\n📌 경험치 3배 버프 이벤트 진행 중\n▶ 마법 시전', '', 340000.00, 1700),
(11737, 1, '🏹 활의 전설: 쉐도우 아처', '', '🎯 그림자 속에서 적을 암살하세요\n✨ 로그라이크 방식의 매번 새로운 스테이지\n💰 시작 시 강력한 활 선택권 지급\n▶ 사냥 시작', '', 1630000.00, 8150),
(11738, 1, '🦒 쥬라기 타이쿤: 공룡 공원', '', '🦁 멸종된 공룡들을 부활시키세요\n✨ 나만의 공룡 파크 건설과 관객 유치\n📌 티라노사우르스 화석 증정\n▶ 파크 건설', '', 1020000.00, 5100),
(11739, 1, '⚔️ 소드 나이트: 검사의 긍지', '', '🔥 쾌감 넘치는 횡스크롤 액션 RPG\n✨ 화려한 콤보와 실시간 결투장\n💰 유료 강화 주문서 50장 지원\n▶ 검술 연마', '', 410000.00, 2050),
(11740, 1, '🚆 지하철 기관사 시뮬레이터', '', '🛤️ 안전하게 승객을 운송하세요\n✨ 현실적인 노선과 정차 시스템 구현\n📌 신규 노선 오픈 기념 승무원 복장\n▶ 운행 시작', '', 1700000.00, 8500),
(11741, 1, '🛸 스페이스 슈터: 에일리언', '', '👽 쏟아지는 탄막을 피하고 적을 격파!\n✨ 기체 업그레이드와 보조 드론 시스템\n💰 보석 1,000개 즉시 지급 쿠폰\n▶ 출격하기', '', 1090000.00, 5450),
(11742, 1, '👗 모델 라이프: 스타 코디', '', '✨ 런웨이의 주인공은 바로 당신\n💖 수천 가지 의상으로 꾸미는 재미\n📌 명품 핸드백 사은품 즉시 증정\n▶ 코디 시작', '', 480000.00, 2400),
(11743, 1, '🛡️ 철옹성 디펜스: 전략의 왕', '', '⚔️ 어떤 공격도 막아내는 무적의 성벽\n✨ 영웅 배치와 함정 설치의 재미\n💰 타워 업그레이드 비용 무료 이벤트\n▶ 수비하기', '', 1770000.00, 8850),
(11744, 1, '🏔️ 설산 서바이벌: 얼음왕국', '', '❄️ 추위와 굶주림 속에서 살아남기\n✨ 생존 기술 습득과 베이스캠프 구축\n📌 방한복 세트 100% 무료 지급\n▶ 생존 시작', '', 1160000.00, 5800),
(11745, 1, '🃏 홀덤 마스터: 라스베이거스', '', '💰 인생 역전을 꿈꾸는 올인 승부\n✨ 공정한 패 분배와 실시간 랭킹 시스템\n📌 신규 입장 시 5억 골드 증정\n▶ 베팅하기', '', 550000.00, 2750),
(11746, 1, '🐹 햄스터 월드컵: 달리기 대전', '', '⚽ 햄스터들의 귀여운 육상 경기\n✨ 나만의 선수 훈련과 컨디션 관리\n💰 황금 해바라기씨 팩 증정 중\n▶ 경기 시작', '', 1840000.00, 9200),
(11747, 1, '🧙 미소녀 전사: 발키리 소환', '', '✨ 여신들과 함께하는 화려한 모험\n⚔️ 애니메이션 같은 스킬 연출\n🎁 100연차 뽑기권 즉시 지급\n▶ 소환하기', '', 1230000.00, 6150),
(11748, 1, '🚔 범죄 도시: 경찰 강력반', '', '🚨 범죄 조직 소탕을 위한 잠입 수사\n✨ 박진감 넘치는 카체이싱과 검거 액션\n📌 특수 경찰 장비 세트 지원\n▶ 수사 시작', '', 620000.00, 3100),
(11749, 1, '🎮 미니 게임 천국: 랜덤 팩', '', '🕹️ 100가지 짧고 굵은 게임 모음\n✨ 친구와 함께 즐기는 랭킹 경쟁\n💰 신규 가입 시 광고 제거권 증정\n▶ 게임 선택', '', 1910000.00, 9550),
(11750, 1, '🧚 요정 마을: 원더 가든', '', '🌸 잃어버린 요정들의 마을을 찾으세요\n✨ 꽃을 심고 나비를 부르는 힐링 게임\n💰 정원 꾸미기 아이템 풀세트\n▶ 가든 꾸미기', '', 1300000.00, 6500);
