INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11751, 1, '⚔️ 소환사의 연대기: 영웅의 탄생', '', '🔥 1,000종의 정령과 함께하는 대서사시\n✨ 눈을 뗄 수 없는 화려한 스킬 연출\n📌 지금 가입 시 전설 소환권 50매 증정\n▶ 모험 시작하기', '', 690000.00, 3450),
(11752, 1, '🎮 아케이드 마스터: 픽셀 배틀', '', '🕹️ 80년대 감성 그대로, 무한 스테이지\n✨ 친구와 실시간 점수 대결 모드 탑재\n💰 주말 한정 코인 무제한 버프 적용\n▶ 게임 시작', '', 1980000.00, 9900),
(11753, 1, '🏹 그림자 헌터: 액션 로그라이크', '', '🔥 매번 바뀌는 맵, 무한한 스킬 조합\n✨ 한 손 조작으로 즐기는 짜릿한 타격감\n📌 신규 챕터 「망령의 숲」 오픈\n▶ 사냥하기', '', 1370000.00, 6850),
(11754, 1, '⚽ 드림 매니저: 축구의 신', '', '🏆 나만의 구단을 세계 최고의 팀으로!\n📊 정교한 데이터 분석과 전술 설정\n💰 신규 감독님 지원금 10만 골드\n▶ 구단 운영', '', 760000.00, 3800),
(11755, 1, '🎴 매직 덱 빌더: 전략의 정점', '', '🧠 두뇌를 자극하는 극한의 카드 배틀\n✨ 나만의 필살기 덱을 완성하세요\n🎁 스타터 패키지 70% 파격 할인\n▶ 배틀 시작', '', 150000.00, 750),
(11756, 1, '🏎️ 니트로 레이싱: 언더그라운드', '', '🔥 아스팔트를 불태우는 극한의 속도\n🏎️ 슈퍼카 풀 튜닝 시스템 완비\n📌 선착순 한정판 엔진 파츠 증정\n▶ 질주하기', '', 1440000.00, 7200),
(11757, 1, '🧩 젤리 팡팡: 퍼즐 아일랜드', '', '🍓 달콤한 젤리들이 팡팡 터지는 쾌감\n✨ 스트레스 풀리는 경쾌한 사운드 효과\n💰 하트 무제한 1시간 쿠폰 즉시 지급\n▶ 퍼즐 풀기', '', 830000.00, 4150),
(11758, 1, '🔫 배틀 필드: 최후의 생존자', '', '💀 100인 중 끝까지 살아남는 자가 승리\n🚁 리얼한 탄도학 기술과 장비 시스템\n📌 신규 유저 생존 키트 무료 지원\n▶ 생존하기', '', 220000.00, 1100),
(11759, 1, '🏰 가디언 디펜스: 성 사수 작전', '', '🛡️ 끊임없이 밀려오는 적을 막아내라\n✨ 전략적인 영웅 배치와 성벽 업그레이드\n💰 오늘만 특수 타워 설치권 증정\n▶ 방어하기', '', 1510000.00, 7550),
(11760, 1, '🎹 비트 스톤: 리듬의 전설', '', '🎶 최신 인기곡과 고전 명곡의 만남\n✨ 완벽한 싱크와 화려한 이펙트의 조화\n🎁 프리미엄 곡 팩 무료 해금 이벤트\n▶ 리듬 타기', '', 900000.00, 4500),
(11761, 1, '🧗 고스트 클라이머: 한계 도전', '', '⛰️ 가파른 절벽을 타고 정상으로!\n✨ 전 세계 명산을 모바일로 정복하세요\n📌 기록 갱신 시 레벨업 가속템 지급\n▶ 등반하기', '', 290000.00, 1450),
(11762, 1, '🍳 마이 셰프 타이쿤: 맛집 경영', '', '🍱 최고의 레시피로 손님을 감동시키세요\n✨ 가게 인테리어부터 분점 확장까지\n💰 오픈 기념 골든 나이프 세트 증정\n▶ 경영 시작', '', 1580000.00, 7900),
(11763, 1, '🧸 온라인 인형 뽑기: 럭키 박스', '', '🎁 스마트폰으로 실제 인형을 뽑으세요\n✨ 집 앞까지 안전하게 무료 배송\n📌 신규 유저 10회 무료 체험권\n▶ 뽑기 시작', '', 970000.00, 4850),
(11764, 1, '🔍 미궁 탈출: 보이지 않는 문', '', '🕵️ 당신의 추리력을 시험하는 고난도 탈출\n✨ 탄탄한 스토리와 몰입감 넘치는 사운드\n💰 힌트 무제한 패스권 주말 한정 세일\n▶ 탈출하기', '', 360000.00, 1800),
(11765, 1, '🧟 서바이버: 좀비 시티', '', '💀 굶주린 좀비 떼로부터 거점을 사수하라\n🔧 다양한 무기 개조와 생존자 구출\n📌 접속 시 보급 물자 상자 10개 증정\n▶ 생존하기', '', 1650000.00, 8250),
(11766, 1, '🏌️ 리얼 골프 챔피언십 2026', '', '⛳ 실제 필드에 있는 듯한 몰입감\n✨ 정교한 바람과 지형 물리 엔진 적용\n💰 홀인원 달성 시 유료 캐시 대량 증정\n▶ 티오프', '', 1040000.00, 5200),
(11767, 1, '🚢 오션 로드: 대항해 시대', '', '🌊 미지의 대륙을 발견하고 무역을 독점하라\n⚔️ 해적 소탕과 강력한 함대 구축의 재미\n📌 신규 제독님을 위한 범선 무료 증정\n▶ 항해 시작', '', 430000.00, 2150),
(11768, 1, '👻 심야 괴담: 숨바꼭질', '', '😱 공포의 술래를 피해 아침을 맞이하라\n✨ 멀티플레이로 즐기는 극한의 긴장감\n💰 캐릭터 전용 야간 투시경 아이템 증정\n▶ 게임 시작', '', 1720000.00, 8600),
(11769, 1, '🐉 드래곤 진화: 각성의 순간', '', '🔥 아기 드래곤을 전설의 신수로 키우세요\n✨ 화려한 진화 단계와 가공할 파괴력\n📌 전설 등급 드래곤 알 100% 지급\n▶ 육성하기', '', 1110000.00, 5550),
(11770, 1, '🏀 스트릿 농구: 슬램 마스터', '', '🔥 3대3 실시간 매칭 길거리 농구 배틀\n✨ 화려한 에어워크와 덩크슛의 쾌감\n💰 신규 가입 시 레어 코스튬 증정\n▶ 코트 입장', '', 500000.00, 2500),
(11771, 1, '🐹 힐링 숲: 햄스터 마을', '', '✨ 햄찌들이 살아가는 포근한 마을 이야기\n💖 보기만 해도 마음이 편안해지는 방치형\n📌 지금 시작하면 프리미엄 씨앗 증정\n▶ 마을 가꾸기', '', 1790000.00, 8950),
(11772, 1, '🀄 타짜의 손맛: 맞고 대전', '', '💰 짜릿한 심리전과 화끈한 올인 승부\n✨ 무제한 무료 충전과 데일리 보너스\n📌 지금 접속 시 루비패 스킨 증정\n▶ 한판 하기', '', 1180000.00, 5900),
(11773, 1, '🧚 루나 판타지: 요정의 나라', '', '🌸 꿈속 같은 그래픽과 감동적인 스토리\n✨ 나만의 요정 친구와 함께 떠나는 모험\n💰 모험가 정착 지원금 50만 골드\n▶ 여행 시작', '', 570000.00, 2850),
(11774, 1, '🛸 스타 가디언: 함대 전술', '', '🌌 은하계를 지키는 거대 함대의 사령관\n✨ 실시간 전략 시뮬레이션의 진수\n📌 한정판 우주 전함 설계도 배포\n▶ 우주 출격', '', 1860000.00, 9300),
(11775, 1, '🛹 익스트림 스케이트보드 2026', '', '🔥 거리의 모든 것이 나만의 스테이지\n✨ 수천 가지 기술 조합과 콤보 경쟁\n💰 랭킹 진입 시 유료 기어 세트 증정\n▶ 보드 타기', '', 1250000.00, 6250),
(11776, 1, '🎣 프로 피싱: 전설의 대어', '', '🌊 전 세계 낚시 명소에서 즐기는 짜릿한 릴링\n✨ 실제 낚시꾼이 추천하는 리얼한 손맛\n📌 전설의 낚싯대 세트 기간 한정 제공\n▶ 낚시 시작', '', 640000.00, 3200),
(11777, 1, '🦸 히어로 리그: 지구 수호대', '', '🔥 강력한 히어로들을 모아 팀을 결성하라\n⚔️ 화려한 연계 스킬과 대규모 연합전\n💰 무료 소환 100회권 즉시 지급 쿠폰\n▶ 각성하기', '', 1930000.00, 9650),
(11778, 1, '🏢 부동산 킹: 빌딩 타이쿤', '', '💰 건물주에서 도시 설계자까지!\n✨ 월세 수익으로 자산을 불려보세요\n📌 신규 투자자용 황금 건물권 증정\n▶ 경영 시작', '', 1320000.00, 6600),
(11779, 1, '🚜 목가적 풍경: 해피 파머', '', '🌽 땀의 결실을 맺는 평화로운 농촌 생활\n✨ 작물 재배부터 가공 판매까지 올인원\n💰 신형 트랙터 장비 무료 업그레이드\n▶ 농사 짓기', '', 710000.00, 3550),
(11780, 1, '🎱 당구의 정석: 온라인 3쿠션', '', '✨ 완벽한 각도 계산, 최고의 물리 엔진\n🏆 전 세계 랭커들과의 1:1 진검 승부\n📌 주말 한정 프리미엄 큐대 대여\n▶ 경기 시작', '', 100000.00, 500),
(11781, 1, '🦊 신령 소환: 동양 판타지', '', '✨ 전설 속 신령들과 함께하는 수행길\n⚔️ 턴제 전략의 깊이와 화려한 도술\n💰 7일 접속 시 구미호 소환권 증정\n▶ 수행 시작', '', 1390000.00, 6950),
(11782, 1, '⛏️ 골드 마이너: 황금광 시대', '', '💎 땅속 깊은 곳 보물을 찾아 떠나세요\n✨ 자동 채굴기와 강력한 폭탄 아이템\n📌 황금 원석 발견 확률 2배 이벤트\n▶ 채굴 시작', '', 780000.00, 3900),
(11783, 1, '🎨 컬러 힐링: 명화 컬러링', '', '✨ 숫자를 따라 색칠하는 여유로운 시간\n💖 완성된 작품으로 개인 전시회 개최\n💰 유료 도안 30종 무료 개방 중\n▶ 색칠하기', '', 170000.00, 850),
(11784, 1, '🚒 긴급구조 119: 히어로즈', '', '🔥 화재 진압부터 구조 활동까지 완벽 체험\n✨ 실제 소방 장비 디테일 구현\n📌 소방대원 캐릭터 스킨 100% 증정\n▶ 출동하기', '', 1460000.00, 7300),
(11785, 1, '🏰 삼국지: 제왕의 길', '', '⚔️ 천하를 호령하는 진정한 군주가 되라\n✨ 대규모 군단전과 치열한 성점령전\n📌 명장 관우 영웅 카드 즉시 지급\n▶ 출전하기', '', 850000.00, 4250),
(11786, 1, '🐱 캣 파라다이스: 카페 경영', '', '☕ 귀여운 고양이들과 함께 만드는 디저트\n✨ 손님들을 매료시킬 특별한 레시피\n💰 한정판 캣타워 가구 세트 선물\n▶ 카페 개업', '', 240000.00, 1200),
(11787, 1, '🏃 스카이 런: 구름 위의 질주', '', '🔥 끝없이 펼쳐진 하늘길을 달려보세요\n✨ 중독성 강한 조작과 속도감의 끝\n💰 신규 캐릭터 날개 신발 즉시 증정\n▶ 달리기', '', 1530000.00, 7650),
(11788, 1, '🧙 매직 아카데미: 수습 마법사', '', '✨ 화려한 마법 기술을 배우고 연마하세요\n🔥 강력한 몬스터를 물리치는 지팡이 수집\n📌 경험치 부스트 물약 대량 지급\n▶ 마법 시전', '', 920000.00, 4600),
(11789, 1, '🏹 활의 달인: 명궁 챌린지', '', '🎯 바람의 세기를 계산해 과녁을 맞추세요\n✨ 실시간 랭킹 시스템과 다양한 활 커스텀\n💰 다이아몬드 500개 지급 쿠폰\n▶ 활 쏘기', '', 310000.00, 1550),
(11790, 1, '🦒 야생 동물원: 월드 사파리', '', '🦁 희귀 동물을 구조하고 보호하세요\n✨ 관람객을 위한 환상적인 사파리 투어\n📌 아기 호랑이 분양권 즉시 증정\n▶ 공원 개장', '', 1600000.00, 8000),
(11791, 1, '⚔️ 소드 마스터: 액션 RPG', '', '🔥 극한의 타격감을 선사하는 고퀄리티 액션\n✨ 수만 명의 유저와 함께하는 필드 레이드\n💰 지금 접속 시 전설 무기 상자 증정\n▶ 검술 연마', '', 990000.00, 4950),
(11792, 1, '🚆 대륙 철도: 열차 기관사', '', '🛤️ 대륙을 가로지르는 열차의 기관사\n✨ 현실적인 계기판 조작과 풍경 구현\n📌 유럽 노선 패키지 무료 해금\n▶ 운전 시작', '', 380000.00, 1900),
(11793, 1, '🛸 에일리언 헌터: 행성 수비대', '', '👽 쏟아지는 외계 군단을 섬멸하라\n✨ 최첨단 화기와 강력한 스킬 업그레이드\n💰 강화 성공 확률 100% 버프 이벤트\n▶ 사격하기', '', 1670000.00, 8350),
(11794, 1, '👗 패션 모델: 런웨이 스타', '', '✨ 당신의 스타일링으로 세계를 매혹하라\n💖 화려한 코스튬과 메이크업의 조화\n📌 신상 브랜드 의상 세트 무료 증정\n▶ 코디 시작', '', 1060000.00, 5300),
(11795, 1, '🛡️ 이지스 디펜스: 방패의 전설', '', '⚔️ 공격은 최대의 방어! 성벽을 사수하라\n✨ 영웅 조합으로 완성하는 무적의 전술\n💰 방어 시설 업그레이드 할인권 증정\n▶ 수비하기', '', 450000.00, 2250),
(11796, 1, '🏔️ 얼어붙은 땅: 생존의 법칙', '', '❄️ 극한의 추위 속에서 불을 피우고 생존하라\n✨ 리얼한 생존 시뮬레이션과 거점 구축\n📌 방한 패키지 및 식량 꾸러미 지급\n▶ 생존 시작', '', 1740000.00, 8700),
(11797, 1, '🃏 마카오 홀덤: 프로 대전', '', '💰 숨 막히는 심리전, 진정한 승부사들의 게임\n✨ 전 세계 유저와 실시간 칩 경쟁\n📌 신규 가입 시 10억 칩 즉시 지원\n▶ 베팅하기', '', 1130000.00, 5650),
(11798, 1, '🐹 햄스터 올림픽: 육상 대전', '', '🏃 작고 귀여운 햄스터들의 위대한 도전\n✨ 훈련을 통해 세계 기록을 갱신하세요\n💰 한정판 운동복 코스튬 세트 증정\n▶ 경기 시작', '', 520000.00, 2600),
(11799, 1, '🧙 발키리 연대기: 여신의 부름', '', '✨ 아름다운 여신들과 함께하는 전략 전투\n⚔️ 압도적인 퀄리티의 스킬 컷신 제공\n🎁 신규 유저 100연 뽑기권 전원 증정\n▶ 소환하기', '', 1810000.00, 9050),
(11800, 1, '🚔 특수 경찰: 시티 가디언즈', '', '🚨 도심의 범죄를 근절하는 특수 부대원\n✨ 박진감 넘치는 추격전과 검거 액션\n📌 특수 경찰 전용 차량 무료 대여\n▶ 수사 시작', '', 1200000.00, 6000);
