INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11851, 1, '🏰 다크 소울 리버스', '', '🔥 죽음조차 즐거움이 되는 하드코어 액션\n⚔️ 보스의 패턴을 파악하고 전설을 쓰세요\n📌 지금 접속 시 부활의 주문서 10장 증정\n▶ 도전하기', '', 490000.00, 2450),
(11852, 1, '🧩 캔디 매치: 스윗 런', '', '🍭 달콤함이 터지는 팡팡 퍼즐의 세계\n✨ 3,000개 이상의 방대한 스테이지 업데이트\n💰 신규 유저 무제한 하트 1시간 제공\n▶ 퍼즐 시작', '', 1780000.00, 8900),
(11853, 1, '🚀 갤럭시 익스플로러', '', '🌌 끝없는 우주를 탐사하고 자원을 채취하세요\n✨ 나만의 우주 기지를 건설하고 방어하기\n📌 스타터 함선 무료 강화 부품 지원\n▶ 우주로 출발', '', 1170000.00, 5850),
(11854, 1, '⚽ 축구왕 2026: 매니저', '', '🏆 당신의 전략으로 팀을 우승으로 이끄세요\n📊 실시간 선수 스탯 반영 및 전술 시뮬레이션\n💰 전설의 감독 팩 즉시 지급 이벤트\n▶ 구단주 되기', '', 560000.00, 2800),
(11855, 1, '🗡️ 도트 나이트: 방치형 RPG', '', '✨ 레트로 감성 도트 액션의 진수\n🔥 수집욕을 자극하는 다양한 영웅 캐릭터\n🎁 지금 접속 시 다이아 10,000개 증정\n▶ 모험 떠나기', '', 1850000.00, 9250),
(11856, 1, '🏢 커피 타이쿤: 바리스타킹', '', '☕ 나만의 레시피로 카페 프랜차이즈 도전\n✨ 몰려드는 손님들을 만족시키고 매장 확장\n💰 오픈 기념 황금 원두 아이템 증정\n▶ 경영 시작', '', 1240000.00, 6200),
(11857, 1, '🔫 모던 건즈: 택티컬', '', '🎯 초정밀 그래픽으로 구현된 FPS의 정석\n✨ 전 세계 유저와 즐기는 실시간 팀 배틀\n📌 신규 총기 「M4 커스텀」 업데이트\n▶ 사격 시작', '', 630000.00, 3150),
(11858, 1, '🐱 냥이 랜드: 힐링 정원', '', '🏝️ 귀여운 고양이들과 함께하는 평화로운 일상\n✨ 정원을 꾸미고 고양이 친구들을 초대하세요\n💰 웰컴 기프트로 프리미엄 간식 상자 지급\n▶ 힐링 시작', '', 1920000.00, 9600),
(11859, 1, '🏹 고스트 아처: 로그라이크', '', '🎯 단 한 발의 화살로 전장을 지배하라\n✨ 매번 바뀌는 무작위 스킬 조합의 재미\n📌 전설 등급 활 제작 도면 지원\n▶ 활 쏘기', '', 1310000.00, 6550),
(11860, 1, '🧟 좀비 헌터: 라스트 데이', '', '💀 인류의 마지막 생존자가 되어 좀비를 소탕하세요\n🔧 무기 개조 시스템과 방벽 강화 기능\n💰 초보 생존자 전용 전투 패키지 증정\n▶ 생존하기', '', 700000.00, 3500),
(11861, 1, '🎹 리듬 스타: 팝 에디션', '', '🎶 인기 팝송을 리듬 게임으로 즐기세요\n✨ 화려한 노트 이펙트와 캐릭터 커스텀\n🎁 프리미엄 음원 5곡 무료 해금\n▶ 리듬 타기', '', 1990000.00, 9950),
(11862, 1, '🚜 농부의 꿈: 힐링 팜', '', '🌽 정성껏 가꾼 작물로 풍성한 수확을!\n✨ 귀여운 동물들과 함께하는 농장 일기\n💰 농기구 업그레이드 20% 세일\n▶ 농사 짓기', '', 1380000.00, 6900),
(11863, 1, '🧗 등반의 정석: 수직 액션', '', '⛰️ 손에 땀을 쥐게 하는 절벽 등반 챌린지\n✨ 전 세계 명산을 정복하고 랭킹에 도전\n📌 클라이밍 로프 강화 아이템 증정\n▶ 등반하기', '', 770000.00, 3850),
(11864, 1, '🧪 퍼즐 마스터: 탈출의 방', '', '🕵️ 당신의 두뇌를 시험하는 기묘한 장치들\n✨ 숨겨진 단서를 찾아 방을 탈출하세요\n💰 힌트 팩 무제한 이용권 기간 한정 판매\n▶ 탈출 시작', '', 160000.00, 800),
(11865, 1, '🚢 대해적 시대: 해상권 쟁탈', '', '🌊 거대한 범선을 타고 미지의 바다를 정복\n⚔️ 박진감 넘치는 해상전과 보물 탐사\n📌 황금 보물상자 열쇠 3개 증정\n▶ 항해 시작', '', 1450000.00, 7250),
(11866, 1, '🏌️ 프로 골프: 온라인 샷', '', '⛳ 실제 필드의 현장감을 손끝으로 느끼세요\n✨ 전 세계 골퍼들과 실시간 1:1 대전\n💰 홀인원 달성 시 한정판 큐 증정\n▶ 티오프', '', 840000.00, 4200),
(11867, 1, '🐉 드래곤 진화: 육성 일기', '', '🔥 전설의 드래곤을 부화시키고 진화시키세요\n✨ 속성별 다양한 드래곤 수집의 재미\n📌 희귀 알 부화 촉진제 10개 지급\n▶ 육성하기', '', 230000.00, 1150),
(11868, 1, '🏀 덩크 마스터: 농구의 신', '', '🔥 길거리 농구의 화려한 기술을 체험하세요\n✨ 나만의 선수를 육성하여 리그 평정\n💰 신규 유저용 농구화 세트 증정\n▶ 경기 시작', '', 1520000.00, 7600),
(11869, 1, '🐹 햄스터 마켓: 힐링 타이쿤', '', '🥖 귀여운 햄스터들이 운영하는 시장\n✨ 매장을 꾸미고 다양한 물건을 판매하세요\n💰 최고급 해바라기씨 100개 선물\n▶ 경영 시작', '', 910000.00, 4550),
(11870, 1, '🀄 한게임 맞고: 클래식', '', '💰 짜릿한 타격감과 정통 맞고의 재미\n✨ 끊이지 않는 무료 충전 서비스 제공\n📌 오늘 가입 시 VIP 아바타 증정\n▶ 한판 하기', '', 300000.00, 1500),
(11871, 1, '🧚 머지 가든: 정령의 섬', '', '✨ 같은 꽃을 합쳐서 더 큰 정원을 만드세요\n🌸 지친 일상에 힐링을 주는 퍼즐 게임\n💰 섬 확장권 50% 할인 이벤트\n▶ 가꾸기', '', 1590000.00, 7950),
(11872, 1, '🛸 에일리언 슈터: 은하 방위', '', '🌌 지구를 침공하는 외계 함대를 격파하라\n✨ 화려한 탄막 액션과 기체 진화 시스템\n📌 강화 주문서 50장 즉시 지급\n▶ 출격하기', '', 980000.00, 4900),
(11873, 1, '🛹 스케이트 런: 시티 트릭', '', '🔥 도심 장애물을 화려한 트릭으로 돌파\n✨ 나만의 보드 커스터마이징 기능\n💰 랭킹 이벤트 참여 시 레어 데크 증정\n▶ 보드 타기', '', 370000.00, 1850),
(11874, 1, '🎣 도시 강태공: 리얼 낚시', '', '🌊 전 세계 낚시 명소의 현장감을 그대로\n✨ 짜릿한 손맛과 대어 낚시의 성취감\n📌 전설의 찌 아이템 7일 체험권\n▶ 낚시 시작', '', 1660000.00, 8300),
(11875, 1, '🦸 슈퍼 히어로: 어벤징', '', '🔥 강력한 히어로 팀을 결성하고 악을 처단\n⚔️ 세상을 구하는 거대 보스 토벌전\n💰 유료 캐릭터 선택권 즉시 배포\n▶ 각성하기', '', 1050000.00, 5250),
(11876, 1, '🏢 건물주 타이쿤: 강남의 왕', '', '💰 부동산 투자로 엄청난 수익을 창출하세요\n✨ 전 세계 랜드마크를 내 소유로!\n📌 신규 유저 투자금 2배 버프 지급\n▶ 경영 시작', '', 440000.00, 2200),
(11877, 1, '🚜 리틀 파머: 수확의 계절', '', '🌽 땀 흘리는 즐거움, 풍성한 가을 수확\n✨ 이웃 농장과 교류하고 작물을 나누세요\n💰 프리미엄 씨앗 주머니 5개 증정\n▶ 농사 시작', '', 1730000.00, 8650),
(11878, 1, '🎱 빌리어드 전설: 8볼 킹', '', '✨ 정교한 물리 엔진으로 구현된 당구의 정석\n🏆 실시간 랭킹전과 친구 대전 지원\n📌 한정판 큐대 스킨 획득 이벤트\n▶ 경기 시작', '', 1120000.00, 5600),
(11879, 1, '🦊 요괴 판타지: 수행의 길', '', '✨ 신비로운 동양 판타지 세계로의 여행\n⚔️ 화려한 도술 액션과 영웅 수집\n💰 7일 출석 시 전설 요괴 소환권 증정\n▶ 수행 시작', '', 510000.00, 2550),
(11880, 1, '⛏️ 골드 마이너: 지하 탐험', '', '💎 땅속 깊이 숨겨진 보물을 찾아내세요\n✨ 채굴 장비 강화와 자동 로봇 시스템\n📌 연료 보급 아이템 50개 지급\n▶ 채굴 시작', '', 1800000.00, 9000),
(11881, 1, '🎨 픽셀 컬러: 힐링 타임', '', '✨ 스트레스 없는 무념무상의 색칠 시간\n💖 귀여운 픽셀 아트를 완성해 보세요\n💰 프리미엄 도안 전면 무료 개방\n▶ 색칠하기', '', 1190000.00, 5950),
(11882, 1, '🚒 파이어 파이터: 긴급 출동', '', '🔥 불길을 뚫고 생명을 구하는 소방관 체험\n✨ 실제 소방차 운전 및 화재 진압 시뮬레이션\n📌 소방대원 장비 풀세트 무료 지급\n▶ 출동하기', '', 580000.00, 2900),
(11883, 1, '🏰 삼국지 영웅전: 무쌍', '', '⚔️ 역사 속 무장들이 펼치는 화려한 액션\n✨ 수천 명의 적을 베어 넘기는 짜릿함\n📌 전설의 명마 「청룡도」 증정\n▶ 참전하기', '', 1870000.00, 9350),
(11884, 1, '🐱 냐옹 카페: 힐링 베이커리', '', '☕ 귀여운 고양이들과 함께 빵을 구워요\n✨ 달콤한 빵 냄새 가득한 힐링 공간\n💰 인테리어 가구 세트 무료 배포\n▶ 카페 개업', '', 1260000.00, 6300),
(11885, 1, '🏃 언리미티드 런: 서브웨이', '', '🔥 장애물을 피해 끝없이 달리는 질주\n✨ 친구보다 더 멀리, 더 빠르게 도전\n💰 캐릭터 가속 부스터 즉시 지급\n▶ 달리기', '', 650000.00, 3250),
(11886, 1, '🧙 매직 위저드: 스펠 마스터', '', '✨ 쏟아지는 화려한 마법의 향연\n🔥 지팡이 커스텀과 고대 마법 연구\n📌 마법 결정체 1,000개 지원 쿠폰\n▶ 마법 시작', '', 1940000.00, 9700),
(11887, 1, '🏹 활의 달인: 킹 오브 양궁', '', '🎯 단 한 발로 승부를 가르는 고요한 긴장감\n✨ 온라인 실시간 양궁 랭킹전 지원\n💰 전용 활 스킨 무료 배포 이벤트\n▶ 활 쏘기', '', 1330000.00, 6650),
(11888, 1, '🦒 주 타이쿤: 동물 보호구역', '', '🦁 멸종 위기 동물을 구조하고 돌보세요\n✨ 나만의 사파리 파크를 꾸미는 즐거움\n📌 아기 사자 분양권 즉시 증정\n▶ 공원 열기', '', 720000.00, 3600),
(11889, 1, '⚔️ 소드 마스터: 레전드', '', '🔥 타격감 폭발하는 액션 RPG의 끝판왕\n✨ 화려한 콤보와 실시간 PVP 대전\n💰 무기 강화석 100개 지급 이벤트\n▶ 검술 연마', '', 110000.00, 550),
(11890, 1, '🚆 지하철 드라이버: 서울', '', '🛤️ 서울 주요 노선을 직접 운전해 보세요\n✨ 실제 기관실과 유사한 조작감 체험\n📌 신규 노선 패스권 즉시 제공\n▶ 운전 시작', '', 1400000.00, 7000),
(11891, 1, '🛸 갤럭시 슈터: 인베이전', '', '👽 끊임없이 쏟아지는 외계 군단 격파\n✨ 무기 조합을 통한 강력한 공격력\n💰 다이아 3,000개 즉시 지급 이벤트\n▶ 사격하기', '', 790000.00, 3950),
(11892, 1, '👗 패션 스타: 모델의 탄생', '', '✨ 화려한 런웨이, 당신이 바로 주인공\n💖 최신 유행 의상으로 완벽하게 코디\n📌 명품 코디 세트 전원 무료 증정\n▶ 코디 시작', '', 180000.00, 900),
(11893, 1, '🛡️ 캐슬 가디언: 최후의 방어', '', '⚔️ 몰려오는 적들을 성벽 위에서 저지\n✨ 영웅과 타워의 전략적인 조합\n💰 타워 건설 가속 아이템 증정\n▶ 수비하기', '', 1470000.00, 7350),
(11894, 1, '🏔️ 설산 생존: 아이스 에이지', '', '❄️ 극한의 추위 속에서 불을 지피고 생존\n✨ 사냥과 거점 구축으로 살아남으세요\n📌 방한 장비 패키지 무료 지원\n▶ 생존 시작', '', 860000.00, 4300),
(11895, 1, '🃏 포커 킹: 온라인 챔피언십', '', '💰 세계 최고의 포커 고수들과 진검 승부\n✨ 공정한 시스템과 압도적인 긴장감\n📌 가입 시 게임 머니 1억 골드 증정\n▶ 베팅하기', '', 250000.00, 1250),
(11896, 1, '🐹 햄찌 런: 달리기 왕', '', '🏃 세상에서 제일 빠른 햄스터를 키우세요\n✨ 다양한 코스와 장애물을 돌파하는 재미\n💰 해바라기씨 상자 즉시 지급\n▶ 경기 시작', '', 1540000.00, 7700),
(11897, 1, '🧙 여신 강림: 수집형 RPG', '', '✨ 여신들과 함께 떠나는 신비로운 모험\n⚔️ 감동적인 스토리와 전략적인 전투\n🎁 무료 소환 100회권 즉시 제공\n▶ 소환하기', '', 930000.00, 4650),
(11898, 1, '🚔 경찰 특공대: 테러 작전', '', '🚨 도심의 평화를 지키는 특수 부대원\n✨ 박진감 넘치는 총격전과 전술 액션\n📌 특수 방탄복 아이템 전원 증정\n▶ 수사 시작', '', 320000.00, 1600),
(11899, 1, '🎮 미니 게임 월드: 99가지', '', '🕹️ 한 번 시작하면 멈출 수 없는 미니 게임들\n✨ 친구와 점수 경쟁하고 랭킹 도전\n💰 하트 무제한 충전 버프 쿠폰\n▶ 게임 선택', '', 1610000.00, 8050),
(11900, 1, '🧚 요정 가든: 힐링 퍼즐', '', '🌸 잃어버린 요정들의 숲을 되찾아주세요\n✨ 식물을 키우고 숲을 가꾸는 힐링\n💰 정원 데코 아이템 풀세트 증정\n▶ 가꾸기', '', 1000000.00, 5000);
