INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11901, 1, '🏰 다크 월드: 그림자 성전', '', '🔥 한계를 시험하는 하드코어 액션의 정점\n⚔️ 정교한 컨트롤로 거대 보스를 정복하세요\n📌 신규 기사단 가입 시 강화석 500개 증정\n▶ 도전하기', '', 390000.00, 1950),
(11902, 1, '🧩 캔디 팝: 매콤달콤 퍼즐', '', '🍭 톡톡 터지는 캔디와 함께하는 힐링 타임\n✨ 4,000개 이상의 지루할 틈 없는 스테이지\n💰 주말 한정 무제한 하트 부스터 제공\n▶ 퍼즐 시작', '', 1680000.00, 8400),
(11903, 1, '🚀 갤럭시 엠파이어: 기지 건설', '', '🌌 나만의 우주 함대를 이끌고 행성을 개척하세요\n✨ 실시간 전략 자원 전쟁과 동맹 시스템\n📌 신규 사령관용 초기 정착 팩 지원\n▶ 우주로 출발', '', 1070000.00, 5350),
(11904, 1, '⚽ 풋볼 클럽 2026: 감독의 길', '', '🏆 전 세계 유망주를 발굴하고 팀을 우승으로!\n📊 정교한 매니지먼트와 전술 시뮬레이션\n💰 전설 선수 확정 소환권 100% 증정\n▶ 구단주 되기', '', 460000.00, 2300),
(11905, 1, '🗡️ 도트 판타지: 클래식 소울', '', '✨ 레트로 감성 도트 액션과 현대적 재미의 만남\n🔥 수집욕을 자극하는 개성 넘치는 영웅들\n🎁 지금 가입 시 유료 재화 5,000개 즉시 지급\n▶ 모험 떠나기', '', 1750000.00, 8750),
(11906, 1, '🏢 버거 타이쿤: 쉐프의 탄생', '', '🍔 나만의 레시피로 수제 버거 제국을 건설하세요\n✨ 몰려드는 손님들을 위한 광속 요리 서비스\n💰 오픈 기념 인테리어 가구 세트 증정\n▶ 경영 시작', '', 1140000.00, 5700),
(11907, 1, '🔫 모던 워페어: 특수 전술', '', '🎯 실감나는 타격감, 리얼 밀리터리 FPS\n✨ 전 세계 유저와 실시간 5대5 팀 배틀\n📌 신규 돌격 소총 「K-1A」 업데이트\n▶ 사격 시작', '', 530000.00, 2650),
(11908, 1, '🐱 고양이 마을: 포근한 일상', '', '🏝️ 귀여운 냥이들과 함께하는 힐링 아일랜드\n✨ 섬을 꾸미고 나만의 고양이 정원을 만드세요\n💰 웰컴 기프트로 프리미엄 캣닙 팩 증정\n▶ 힐링 시작', '', 1820000.00, 9100),
(11909, 1, '🏹 활의 전설: 윈드 아처', '', '🎯 바람의 흐름을 읽고 적의 심장을 꿰뚫으라\n✨ 매번 새로운 로그라이크 스킬 조합\n📌 전설 등급 활 강화 재료 즉시 지원\n▶ 활 쏘기', '', 1210000.00, 6050),
(11910, 1, '🧟 데드 좀비: 최후의 요새', '', '💀 인류의 마지막 생존자가 되어 좀비를 막으세요\n🔧 강력한 무기 개조와 생존자 캠프 확장\n💰 초보 생존자 전용 전투 보급품 증정\n▶ 생존하기', '', 600000.00, 3000),
(11911, 1, '🎹 댄싱 비트: 글로벌 스타', '', '🎶 인기 K-POP 곡을 리듬으로 즐기세요\n✨ 화려한 아바타 커스텀과 댄스 배틀\n🎁 프리미엄 멤버십 7일 무료 체험권\n▶ 리듬 타기', '', 1890000.00, 9450),
(11912, 1, '🚜 농장 이야기: 해피 하베스트', '', '🌽 정성껏 가꾼 작물로 풍성한 결실을 맺으세요\n✨ 귀여운 동물들과 함께하는 농장 경영\n💰 창고 확장 비용 50% 타임 세일\n▶ 농사 짓기', '', 1280000.00, 6400),
(11913, 1, '🧗 클라이밍 챔피언: 에베레스트', '', '⛰️ 한계에 도전하는 짜릿한 등반 액션\n✨ 전 세계 유명 산을 정복하고 랭킹 경쟁\n📌 클라이밍 슈즈 강화 가루 증정\n▶ 등반하기', '', 670000.00, 3350),
(11914, 1, '🧪 이스케이프: 비밀의 방', '', '🕵️ 당신의 지능을 시험하는 고난도 탈출 퍼즐\n✨ 숨겨진 단서를 조합해 방을 탈출하세요\n💰 힌트 패키지 주말 90% 한정 특가\n▶ 탈출 시작', '', 1960000.00, 9800),
(11915, 1, '🚢 해적왕의 항해: 대해적', '', '🌊 거대한 함선을 타고 보물섬을 탐험하세요\n⚔️ 박진감 넘치는 해상전과 섬 약탈의 재미\n📌 보물지도 조각 전원 증정 이벤트\n▶ 항해 시작', '', 1350000.00, 6750),
(11916, 1, '🏌️ 골프 킹: 온라인 월드 투어', '', '⛳ 실제 필드의 현장감을 그대로 재현\n✨ 전 세계 유저와 실시간 1:1 대전\n💰 홀인원 달성 시 유료 캐시 대량 지급\n▶ 티오프', '', 740000.00, 3700),
(11917, 1, '🐉 드래곤 에그: 위대한 부화', '', '🔥 전설의 드래곤을 부화시키고 훈련하세요\n✨ 다양한 속성의 드래곤 수집과 진화\n📌 희귀 드래곤 알 가속기 5개 지급\n▶ 육성하기', '', 130000.00, 650),
(11918, 1, '🏀 바스켓 루키: 덩크 챌린지', '', '🔥 길거리 농구의 화려한 기술을 내 손안에\n✨ 나만의 선수를 육성하고 리그 우승 도전\n💰 신규 유저 전용 유니폼 세트 증정\n▶ 경기 시작', '', 1420000.00, 7100),
(11919, 1, '🐹 햄스터 셰프: 맛있는 요리', '', '🥖 귀여운 햄스터 셰프들의 우당탕탕 식당 경영\n✨ 인테리어와 메뉴 개발의 무한 재미\n💰 최고급 식재료 상자 10개 선물\n▶ 요리 시작', '', 810000.00, 4050),
(11920, 1, '🀄 맞고의 고수: 판돈을 키워라', '', '💰 짜릿한 손맛과 심리전의 묘미\n✨ 끊이지 않는 무료 게임머니 충전 서비스\n📌 오늘 가입 시 VIP 한정판 패 증정\n▶ 한판 하기', '', 200000.00, 1000),
(11921, 1, '🧚 머지 가든: 정령의 숲', '', '✨ 같은 꽃을 합쳐서 더 큰 정원을 만드세요\n🌸 지친 일상 속 힐링을 선사하는 퍼즐\n💰 정원 확장 아이템 30% 즉시 할인\n▶ 가꾸기', '', 1490000.00, 7450),
(11922, 1, '🛸 에일리언 슈터: 지구의 희망', '', '🌌 지구를 위협하는 외계 함대를 섬멸하라\n✨ 화려한 탄막과 강력한 기체 개조\n📌 무기 강화 주문서 100장 즉시 지급\n▶ 출격하기', '', 880000.00, 4400),
(11923, 1, '🛹 스케이트 시티: 프리스타일', '', '🔥 도심 장애물을 화려한 트릭으로 질주하세요\n✨ 나만의 보드 디자인과 기술 조합\n💰 랭킹 이벤트 참여 시 한정판 데크 증정\n▶ 보드 타기', '', 270000.00, 1350),
(11924, 1, '🎣 빅 피싱: 리얼 낚시 광장', '', '🌊 전 세계 바다에서 즐기는 정교한 낚시\n✨ 짜릿한 손맛과 도감 채우기의 성취감\n📌 전설의 미끼 세트 1주일 사용권\n▶ 낚시 시작', '', 1560000.00, 7800),
(11925, 1, '🦸 울트라 히어로: 악당 소탕', '', '🔥 강력한 히어로 군단을 결성하고 세상을 구하라\n⚔️ 거대 보스 레이드와 화려한 스킬\n💰 유료 영웅 선택권 무료 배포 중\n▶ 각성하기', '', 950000.00, 4750),
(11926, 1, '🏢 시티 타이쿤: 부동산 마스터', '', '💰 전 세계 랜드마크를 소유하고 수익을 창출하세요\n✨ 부동산 투자로 엄청난 자산가 되기\n📌 신규 유저 투자금 2배 부스트 지급\n▶ 경영 시작', '', 340000.00, 1700),
(11927, 1, '🚜 마이 리틀 팜: 시골 생활', '', '🌽 땀 흘리는 즐거움, 풍성한 수확의 계절\n✨ 이웃과 소통하며 함께 키우는 농장\n💰 프리미엄 트랙터 3일 무료 대여권\n▶ 농사 시작', '', 1630000.00, 8150),
(11928, 1, '🎱 당구 전설: 온라인 토너먼트', '', '✨ 0.1도의 오차도 허용 않는 정교한 물리\n🏆 실시간 랭킹 시스템과 글로벌 1:1 대전\n📌 한정판 골든 큐대 조각 이벤트\n▶ 경기 시작', '', 1020000.00, 5100),
(11929, 1, '🦊 신선기: 요괴의 복수', '', '✨ 신비로운 동양 판타지 세계로의 초대\n⚔️ 화려한 도술 액션과 수집형 RPG\n💰 7일 출석 시 전설 동료 100% 증정\n▶ 수행 시작', '', 410000.00, 2050),
(11930, 1, '⛏️ 드릴 킹: 지구 속 보물', '', '💎 땅속 깊이 숨겨진 다이아몬드를 찾으세요\n✨ 드릴 강화와 자동 채굴 로봇 시스템\n📌 연료 충전 아이템 100개 지급\n▶ 채굴 시작', '', 1700000.00, 8500),
(11931, 1, '🎨 픽셀 컬러링: 힐링 아트', '', '✨ 스트레스 없는 무념무상의 색칠 타임\n💖 귀여운 픽셀 캐릭터들을 완성하세요\n💰 프리미엄 도안 기간 한정 무료 개방\n▶ 색칠하기', '', 1090000.00, 5450),
(11932, 1, '🚒 파이어 파이터: 긴급 구조', '', '🔥 불길을 뚫고 생명을 구하는 영웅 이야기\n✨ 실제 소방차 운전 및 화재 진압 체험\n📌 소방대원 특수 장비 세트 지급\n▶ 출동하기', '', 480000.00, 2400),
(11933, 1, '🏰 삼국지: 무쌍 대전', '', '⚔️ 전장을 휩쓰는 일당백의 짜릿한 액션\n✨ 역사 속 무장들의 화려한 오의 연출\n📌 전설의 명마 「청룡도」 패키지 증정\n▶ 참전하기', '', 1770000.00, 8850),
(11934, 1, '🐱 냐옹 빵집: 제빵 마스터', '', '☕ 귀여운 고양이들과 함께 빵을 구워요\n✨ 달콤한 빵 냄새 가득한 힐링 베이커리\n💰 인테리어 소품 세트 무료 선물\n▶ 카페 개업', '', 1160000.00, 5800),
(11935, 1, '🏃 무한의 달리기: 시티 러너', '', '🔥 장애물을 피해 끝없이 달리는 속도감\n✨ 친구보다 더 멀리, 더 빠르게 도전하세요\n💰 캐릭터 부스트 팩 즉시 지급\n▶ 달리기', '', 550000.00, 2750),
(11936, 1, '🧙 대마법사: 마나 마스터', '', '✨ 화면 가득 쏟아지는 화려한 마법의 향연\n🔥 마법 지팡이 커스텀과 고대 스킬 연구\n📌 마법의 가루 1,000개 지원 쿠폰\n▶ 마법 시작', '', 1840000.00, 9200),
(11937, 1, '🏹 명궁: 궁수의 전설', '', '🎯 단 한 발로 승부를 가르는 정적인 긴장감\n✨ 온라인 실시간 양궁 랭킹전 지원\n💰 전용 화살통 스킨 무료 배포\n▶ 활 쏘기', '', 1230000.00, 6150),
(11938, 1, '🦒 사파리 타이쿤: 야생 동물', '', '🦁 멸종 위기 동물을 구조하고 보호하세요\n✨ 나만의 사파리 파크를 만드는 즐거움\n📌 아기 기린 분양권 즉시 증정\n▶ 공원 열기', '', 620000.00, 3100),
(11939, 1, '⚔️ 소드 레전드: 각성의 칼날', '', '🔥 타격감 폭발하는 고퀄리티 액션 RPG\n✨ 화려한 콤보와 실시간 PVP 대전\n💰 강화 성공률 UP 축복권 지급\n▶ 검술 연마', '', 1910000.00, 9550),
(11940, 1, '🚆 지하철 기관사: 한국 노선', '', '🛤️ 서울부터 전국 노선을 실감나게 운행\n✨ 기관실 내부의 세밀한 조작감 구현\n📌 신규 프리미엄 노선 이용권 제공\n▶ 운전 시작', '', 1300000.00, 6500),
(11941, 1, '🛸 에일리언 건즈: 갤럭틱', '', '👽 끊임없이 쏟아지는 외계 군단을 격파하세요\n✨ 무기 조합을 통한 자신만의 공격 패턴\n💰 보석 3,000개 즉시 지급 이벤트\n▶ 사격하기', '', 690000.00, 3450),
(11942, 1, '👗 패션 모델: 런웨이 스타', '', '✨ 화려한 런웨이, 당신이 패션의 주인공\n💖 최신 트렌드 의상으로 완벽하게 코디\n📌 한정판 드레스 아이템 전원 증정\n▶ 코디 시작', '', 1980000.00, 9900),
(11943, 1, '🛡️ 캐슬 가디언: 최후의 성전', '', '⚔️ 몰려오는 몬스터를 성벽 위에서 저지하라\n✨ 영웅과 타워의 완벽한 전략 조합\n💰 타워 건설 시간 단축 물약 증정\n▶ 수비하기', '', 1370000.00, 6850),
(11944, 1, '🏔️ 설산 생존자: 프로스트', '', '❄️ 영하의 추위에서 불을 지피고 살아남기\n✨ 야생 동물 사냥과 안전 거점 구축\n📌 방한 패키지 100% 무료 지원\n▶ 생존 시작', '', 760000.00, 3800),
(11945, 1, '🃏 포커 챔피언십: 올인', '', '💰 세계 최고의 포커 고수들과 실시간 대결\n✨ 공정한 시스템과 압도적 몰입감\n📌 신규 가입 시 칩 10억 개 증정\n▶ 베팅하기', '', 150000.00, 750),
(11946, 1, '🐹 햄스터 런: 해바라기 원정대', '', '🏃 세상에서 제일 빠른 햄스터를 키워보세요\n✨ 다양한 코스와 장애물 돌파의 재미\n💰 해바라기씨 럭키 박스 전원 지급\n▶ 경기 시작', '', 1440000.00, 7200),
(11947, 1, '🧙 여신 강림: 소환사 연대기', '', '✨ 아름다운 여신들과 떠나는 신비로운 여행\n⚔️ 감동적인 스토리와 전략적인 전투\n🎁 무료 뽑기 200회권 즉시 제공\n▶ 소환하기', '', 830000.00, 4150),
(11948, 1, '🚔 경찰 특공대: 강력반', '', '🚨 도심의 평화를 위협하는 적들을 소탕하라\n✨ 박진감 넘치는 총격전과 전술 액션\n📌 특수 방탄복 아이템 무료 증정\n▶ 수사 시작', '', 220000.00, 1100),
(11949, 1, '🎮 미니 게임 월드: 종합팩', '', '🕹️ 한 번 시작하면 멈출 수 없는 미니 게임 모음\n✨ 친구와 점수 경쟁하고 기록 경신 도전\n💰 하트 무제한 충전 버프 즉시 지급\n▶ 게임 선택', '', 1510000.00, 7550),
(11950, 1, '🧚 요정 정원: 시크릿 가든', '', '🌸 잃어버린 요정들의 안식처를 꾸며주세요\n✨ 식물을 키우고 숲을 복원하는 힐링 퍼즐\n💰 정원 데코 아이템 풀세트 선물\n▶ 가꾸기', '', 900000.00, 4500);
