INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11951, 1, '🐲 드래곤 슬레이어: 서약', '', '🔥 당신의 검 끝에서 시작되는 용의 전설\n⚔️ 거대 드래곤과의 숨막히는 보스 레이드\n📌 지금 접속 시 전설 등급 대검 증정\n▶ 모험 시작', '', 290000.00, 1450),
(11952, 1, '🧩 매직 쥬얼: 3매치 퍼즐', '', '💎 보석을 맞추고 마법의 힘을 해방하세요\n✨ 5,000개 이상의 환상적인 퍼즐 스테이지\n💰 신규 유저용 무제한 아이템 3시간권\n▶ 퍼즐 시작', '', 1580000.00, 7900),
(11953, 1, '🚀 스페이스 오딧세이: 개척', '', '🌌 미지의 은하계를 탐험하고 행성을 정복하세요\n✨ 나만의 우주 정거장 구축과 함대 지휘\n📌 스타터 팩: 고성능 레이더 즉시 지급\n▶ 우주로 출격', '', 970000.00, 4850),
(11954, 1, '⚽ 얼티밋 사커: 월드 컵', '', '🏆 전 세계 유저와 실시간으로 즐기는 축구 피버\n📊 나만의 드림팀 구성 및 전술 최적화\n💰 우승 기념 전설 선수 카드 뽑기권\n▶ 경기 시작', '', 360000.00, 1800),
(11955, 1, '🗡️ 도트 가디언즈: 방치형 RPG', '', '✨ 레트로 도트 감성으로 즐기는 무한 성장\n🔥 바쁜 일상 속에서도 멈추지 않는 모험\n🎁 가입 즉시 다이아 20,000개 선물\n▶ 방치 시작', '', 1650000.00, 8250),
(11956, 1, '☕ 디저트 아일랜드: 타이쿤', '', '🍰 달콤한 디저트로 가득한 나만의 섬 경영\n✨ 전 세계 손님들을 사로잡는 마법의 레시피\n💰 오픈 기념 프리미엄 오븐 세트 증정\n▶ 카페 경영', '', 1040000.00, 5200),
(11957, 1, '🔫 크리티컬 스트라이크: FPS', '', '🎯 단 한 발로 결정되는 승부, 정통 밀리터리 슈팅\n✨ 실시간 랭킹전과 클랜전 완벽 지원\n📌 신규 위장 스킨 「디지털 카모」 지급\n▶ 사격 시작', '', 430000.00, 2150),
(11958, 1, '🐱 고양이 집사: 힐링 하우스', '', '🏠 귀여운 고양이들과 함께하는 아늑한 방 꾸미기\n✨ 고양이들의 고민을 해결하고 친밀도를 높이세요\n💰 웰컴 기프트: 고양이 낚싯대 장난감\n▶ 힐링 시작', '', 1720000.00, 8600),
(11959, 1, '🏹 소울 아처: 영혼의 화살', '', '🎯 적의 영혼을 꿰뚫는 강력한 일격\n✨ 로그라이크 조합으로 매번 새로운 전투 경험\n📌 영웅 등급 화살통 조각 50개 지급\n▶ 활 쏘기', '', 1110000.00, 5550),
(11960, 1, '🧟 서바이벌 Z: 좀비 아포칼립스', '', '💀 굶주린 좀비들로부터 캠프를 방어하세요\n🔧 생존 장비 제작과 동료 모집 시스템\n💰 생존 지원금: 탄약 1,000발 즉시 보급\n▶ 생존하기', '', 500000.00, 2500),
(11961, 1, '🎹 비트 마스터: K-팝 페스티벌', '', '🎶 최신 인기곡을 손끝으로 연주하세요\n✨ 화려한 스테이지 연출과 코스튬 수집\n🎁 신규 유저용 프리미엄 곡 패키지\n▶ 플레이 하기', '', 1790000.00, 8950),
(11962, 1, '🚜 목장 이야기: 그린 팜', '', '🌽 평화로운 목장에서 즐기는 힐링 라이프\n✨ 가축을 키우고 신선한 우유를 생산하세요\n💰 목장 확장 비용 30% 한정 할인\n▶ 목장 시작', '', 1180000.00, 5900),
(11963, 1, '🧗 절벽의 제왕: 익스트림 등반', '', '⛰️ 한계에 도전하는 수직의 짜릿함\n✨ 날씨와 지형에 따른 전략적 등반 기술\n📌 전문가 전용 초크백 아이템 증정\n▶ 등반하기', '', 570000.00, 2850),
(11964, 1, '🧪 미스터리 룸: 탈출의 고수', '', '🕵️ 닫힌 방 안에 숨겨진 진실을 밝히세요\n✨ 두뇌를 자극하는 기발한 트릭과 수수께끼\n💰 힌트 코인 50개 즉시 지급 이벤트\n▶ 탈출 시작', '', 1860000.00, 9300),
(11965, 1, '🚢 캐리비안의 전설: 항해', '', '🌊 대양의 패권자가 되기 위한 거대한 여정\n⚔️ 해상 요새 점령과 보물 약탈의 재미\n📌 전설의 함선 「블랙 펄」 기간 한정 대여\n▶ 항해 시작', '', 1250000.00, 6250),
(11966, 1, '🏌️ 골프 마스터: 리얼 투어', '', '⛳ 실제 골프장의 물리 법칙을 그대로 구현\n✨ 전 세계 골퍼들과 즐기는 실시간 대결\n💰 홀인원 경품: 전용 골프백 스킨\n▶ 티오프', '', 640000.00, 3200),
(11967, 1, '🐉 드래곤 빌리지: 새로운 세대', '', '🔥 드래곤을 수집하고 최강의 팀을 만드세요\n✨ 진화할수록 화려해지는 드래곤의 모습\n📌 희귀 드래곤 선택권 1매 증정\n▶ 부화하기', '', 1930000.00, 9650),
(11968, 1, '🏀 스트릿 후프: 길거리 농구', '', '🔥 3대3 길거리 농구의 화려한 테크닉\n✨ 나만의 아바타와 힙합 감성 커스텀\n💰 신규 가입 시 레어 농구공 지급\n▶ 경기 시작', '', 1320000.00, 6600),
(11969, 1, '🐹 햄찌 파라다이스: 힐링 마을', '', '🥖 귀여운 햄스터들의 평화로운 마을 경영\n✨ 작고 소중한 햄스터들과의 교감\n💰 최고급 해바라기씨 500개 선물\n▶ 마을 열기', '', 710000.00, 3550),
(11970, 1, '🀄 맞고의 신: 대박 스페셜', '', '💰 한 판으로 인생 역전, 짜릿한 승부의 세계\n✨ 매일 터지는 잭팟과 풍성한 무료 보너스\n📌 지금 접속 시 올인 방지 지원금 지급\n▶ 한판 하기', '', 100000.00, 500),
(11971, 1, '🧚 머지 랜드: 신비의 정원', '', '✨ 같은 아이템을 합쳐 마법의 정원을 복구하세요\n🌸 스트레스를 날려주는 힐링 머지 퍼즐\n💰 정원 데코 아이템 1+1 이벤트\n▶ 가꾸기', '', 1390000.00, 6950),
(11972, 1, '🛸 갤럭시 디펜더: 에일리언', '', '🌌 은하계를 침략한 외계 생명체를 저지하라\n✨ 강력한 레이저 무기와 기체 강화 시스템\n📌 공격력 강화 포션 20개 즉시 지급\n▶ 출격하기', '', 780000.00, 3900),
(11973, 1, '🛹 스케이트 보드: 킹 오브 트릭', '', '🔥 화려한 점프와 회전 기술로 거리를 지배하라\n✨ 전 세계 유명 스케이트 파크 완벽 재현\n💰 시즌 패스 50% 할인 쿠폰 증정\n▶ 보드 타기', '', 170000.00, 850),
(11974, 1, '🎣 프로 피싱: 바다 낚시', '', '🌊 전설의 물고기를 낚기 위한 인내와 기술\n✨ 실제 낚시터의 생생한 풍경과 손맛\n📌 프리미엄 낚싯대 세트 3일 체험권\n▶ 낚시 시작', '', 1460000.00, 7300),
(11975, 1, '🦸 히어로 얼라이언스: 각성', '', '🔥 지구를 지키기 위해 결집한 슈퍼 히어로들\n⚔️ 화려한 궁극기와 전략적인 팀 배틀\n💰 유료 스킨 선택 상자 무료 배포\n▶ 각성하기', '', 850000.00, 4250),
(11976, 1, '🏢 빌딩 타이쿤: 글로벌 투자', '', '💰 전 세계 도심의 빌딩을 매입하고 수익을 내세요\n✨ 나만의 빌딩 제국을 만드는 경영 시뮬레이션\n📌 신규 유저 정착 자금 10억 골드\n▶ 경영 시작', '', 240000.00, 1200),
(11977, 1, '🚜 마이 팜: 수확의 기쁨', '', '🌽 자연의 품에서 즐기는 여유로운 농사꾼 생활\n✨ 직접 기른 작물을 시장에 팔아 농장 확장\n💰 고급 비료 아이템 100개 증정\n▶ 농사 시작', '', 1530000.00, 7650),
(11978, 1, '🎱 당구 마스터: 실시간 8볼', '', '✨ 한 치의 오차도 없는 정밀한 당구 물리 엔진\n🏆 전 세계 유저와 즐기는 온라인 토너먼트\n📌 가입 기념 프리미엄 큐 케이스 증정\n▶ 경기 시작', '', 920000.00, 4600),
(11979, 1, '🦊 요괴전: 신비한 모험', '', '✨ 인간과 요괴가 공존하는 동양 판타지\n⚔️ 수집한 요괴들과 함께 펼치는 전략 전투\n💰 7일 연속 접속 시 전설 요괴 소환\n▶ 수행 시작', '', 310000.00, 1550),
(11980, 1, '⛏️ 골드 마이닝: 보석 광산', '', '💎 땅속 깊은 곳 보물을 찾아 떠나는 모험\n✨ 장비 업그레이드로 더 깊고 빠르게 채굴\n📌 채굴용 폭탄 50개 무료 지원\n▶ 채굴 시작', '', 1600000.00, 8000),
(11981, 1, '🎨 픽셀 컬러: 안티 스트레스', '', '✨ 숫자에 따라 색을 칠하며 마음을 정화하세요\n💖 매일 업데이트되는 수천 장의 무료 도안\n💰 모든 광고 제거 기능 3일 체험권\n▶ 색칠하기', '', 990000.00, 4950),
(11982, 1, '🚒 긴급 구조: 소방대원 시뮬', '', '🔥 사이렌을 울리며 화재 현장으로 출동하세요\n✨ 인명 구조와 화재 진압의 긴박한 현장\n📌 소방대원 전용 특수 방수복 지급\n▶ 출동하기', '', 380000.00, 1900),
(11983, 1, '🏰 삼국지: 천하통일 RPG', '', '⚔️ 조조, 유비, 손권과 함께 천하를 도모하라\n✨ 대규모 공성전과 장수들의 화려한 스킬\n📌 신규 군주용 전설 무장 1명 확정\n▶ 참전하기', '', 1670000.00, 8350),
(11984, 1, '🐱 냥이 베이커리: 맛있는 빵', '', '☕ 고양이 셰프가 구워주는 달콤한 빵집 경영\n✨ 아기자기한 소품으로 가게를 꾸며보세요\n💰 오븐 가동 시간 단축 아이템 증정\n▶ 카페 개업', '', 1060000.00, 5300),
(11985, 1, '🏃 언리미티드 런: 사막 탈출', '', '🔥 뜨거운 사막의 장애물을 피해 전력 질주\n✨ 피버 타임을 이용해 최고 기록 경신 도전\n💰 자석 및 보호막 아이템 세트 지급\n▶ 달리기', '', 450000.00, 2250),
(11986, 1, '🧙 매직 아카데미: 마법사 교육', '', '✨ 신비로운 마법 학교의 학생이 되어보세요\n🔥 다양한 마법 속성 조합과 연금술 실험\n📌 마법 책장 가구 아이템 증정\n▶ 마법 시작', '', 1740000.00, 8700),
(11987, 1, '🏹 활의 달인: 온라인 배틀', '', '🎯 전 세계 아처들과 즐기는 실시간 양궁 대전\n✨ 긴박함 속에 터지는 10점 만점의 쾌감\n💰 전용 화살 날개 장식 아이템 증정\n▶ 활 쏘기', '', 1130000.00, 5650),
(11988, 1, '🦒 동물 보호 구역: 타이쿤', '', '🦁 아픈 동물을 치료하고 자연으로 돌려보내세요\n✨ 나만의 동물원을 가꾸는 감동적인 경영\n📌 사육사 전용 유니폼 팩 증정\n▶ 공원 열기', '', 520000.00, 2600),
(11989, 1, '⚔️ 소드 레전드: 마지막 기사', '', '🔥 압도적인 그래픽과 시원한 타격감의 액션\n✨ 화려한 연계기와 실시간 보스 토벌전\n💰 장비 강화 보호 주문서 10장 지급\n▶ 검술 연마', '', 1810000.00, 9050),
(11990, 1, '🚆 리얼 트레인: 전국 노선', '', '🛤️ 실제 기차 노선을 그대로 운행하는 즐거움\n✨ 계절마다 변하는 아름다운 풍경과 조작감\n📌 신규 기관사용 노선 가이드 증정\n▶ 운전 시작', '', 1200000.00, 6000),
(11991, 1, '🛸 에일리언 슈팅: 스페이스 건', '', '👽 은하계를 위협하는 적들을 사정없이 사격하라\n✨ 무기 강화와 화려한 필살기 시스템\n💰 신비한 보석 5,000개 즉시 지급\n▶ 사격하기', '', 590000.00, 2950),
(11992, 1, '👗 패션 모델: 글로벌 아이콘', '', '✨ 세계적인 패션 위크의 주인공이 되세요\n💖 나만의 스타일링으로 심사위원 매료시키기\n📌 명품 핸드백 아이템 전원 증정\n▶ 코디 시작', '', 1880000.00, 9400),
(11993, 1, '🛡️ 캐슬 가디언: 타워 디펜스', '', '⚔️ 성을 지키기 위한 최강의 방어선을 구축하라\n✨ 다양한 타워와 영웅들의 전략적 배치\n💰 초기 자원 2배 획득 버프권 지급\n▶ 수비하기', '', 1270000.00, 6350),
(11994, 1, '🏔️ 설산 서바이벌: 윈터 가드', '', '❄️ 혹한의 추위와 굶주림을 이겨내고 생존하세요\n✨ 낚시, 사냥, 채집을 통한 현실적인 생존\n📌 방한용 텐트 및 침낭 패키지 증정\n▶ 생존 시작', '', 660000.00, 3300),
(11995, 1, '🃏 포커 스타: 라이브 토너먼트', '', '💰 최고의 포커 플레이어를 가리는 짜릿한 승부\n✨ 공정한 카드 분배와 고품격 게임 환경\n📌 신규 유저 정착 자금 5억 골드 증정\n▶ 베팅하기', '', 1950000.00, 9750),
(11996, 1, '🐹 햄찌 런: 치즈 어드벤처', '', '🏃 치즈를 찾아 떠나는 귀여운 햄스터의 질주\n✨ 간단한 터치로 즐기는 캐주얼 러닝 게임\n💰 황금 치즈 간식 아이템 100개 지급\n▶ 경기 시작', '', 1340000.00, 6700),
(11997, 1, '🧙 여신 강림: 엔드리스 월드', '', '✨ 당신의 곁을 지켜줄 아름다운 여신 소환\n⚔️ 전략적인 덱 구성과 화려한 스킬 연출\n🎁 무료 300회 뽑기권 파격 지원 중\n▶ 소환하기', '', 730000.00, 3650),
(11998, 1, '🚔 특수 경찰: 크라임 시티', '', '🚨 범죄 조직을 소탕하고 도시의 평화를 지키세요\n✨ 긴박한 추격전과 정교한 사격 액션\n📌 특수 경찰 배지 아이템 증정\n▶ 수사 시작', '', 120000.00, 600),
(11999, 1, '🎮 미니 게임: 챌린지 100', '', '🕹️ 100가지 이상의 다양한 미니 게임 모음\n✨ 짧은 시간에 즐기는 무한한 즐거움\n💰 랭킹 진입 시 유료 재화 보상 지급\n▶ 게임 선택', '', 1410000.00, 7050),
(12000, 1, '🧚 요정의 정원: 매직 힐링', '', '🌸 삭막한 땅을 아름다운 꽃과 나무로 가꾸세요\n✨ 요정들과 함께하는 평화로운 정원 퍼즐\n💰 정원 데코 풀패키지 즉시 증정\n▶ 가꾸기', '', 800000.00, 4000);
